# --- Terraform Configuration for GCP Infrastructure ---

terraform {
  required_version = ">= 1.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

# Variables for customization
variable "project_id" {
  type        = string
  description = "The ID of the project to create/use"
}

variable "region" {
  type    = string
  default = "us-central1"
}

variable "zone" {
  type    = string
  default = "us-central1-a"
}

provider "google" {
  project = var.project_id
  region  = var.region
}

# 1. Project Services (APIs)
resource "google_project_service" "compute" {
  project = var.project_id
  service = "compute.googleapis.com"
  disable_on_destroy = false
}

# 2. Networking (VPC and Subnet)
resource "google_compute_network" "vpc" {
  name                    = "main-vpc"
  auto_create_subnetworks = false
  depends_on              = [google_project_service.compute]
}

resource "google_compute_subnetwork" "subnet" {
  name          = "main-subnet"
  ip_cidr_range = "10.0.1.0/24"
  region        = var.region
  network       = google_compute_network.vpc.id
}

# 3. Cloud NAT and Router (for private internet access)
resource "google_compute_router" "router" {
  name    = "nat-router"
  network = google_compute_network.vpc.id
  region  = var.region
}

resource "google_compute_router_nat" "nat" {
  name                               = "main-nat"
  router                             = google_compute_router.router.name
  region                             = var.region
  nat_ip_allocate_option             = "AUTO_ONLY"
  source_subnetwork_ip_ranges_to_nat = "ALL_SUBNETWORKS_ALL_IP_RANGES"
}

# 4. Firewall Rules
# Allow Health Checks and LB traffic (GCP ranges)
resource "google_compute_firewall" "allow_lb" {
  name    = "allow-lb-and-healthcheck"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["80"]
  }

  source_ranges = ["130.211.0.0/22", "35.191.0.0/16"]
  target_tags   = ["web-server"]
}

# Allow SSH via IAP
resource "google_compute_firewall" "allow_ssh" {
  name    = "allow-ssh-iap"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["35.235.240.0/20"]
}

# 5. Compute Resources
# Health Check for MIG and LB
resource "google_compute_health_check" "default" {
  name = "http-health-check"
  http_health_check {
    port = 80
  }
}

# Instance Template
resource "google_compute_instance_template" "tpl" {
  name         = "web-template"
  machine_type = "e2-medium"

  disk {
    source_image = "debian-cloud/debian-11"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network    = google_compute_network.vpc.id
    subnetwork = google_compute_subnetwork.subnet.id
  }

  metadata_startup_script = <<-EOT
    #!/bin/bash
    apt-get update
    apt-get install -y apache2
    echo "Hello from Terraform managed instance" > /var/www/html/index.html
  EOT

  tags = ["web-server"]
}

# Managed Instance Group
resource "google_compute_region_instance_group_manager" "mig" {
  name               = "web-mig"
  region             = var.region
  base_instance_name = "web-app"
  target_size        = 2

  version {
    instance_template = google_compute_instance_template.tpl.id
  }

  named_port {
    name = "http"
    port = 80
  }

  auto_healing_policies {
    health_check      = google_compute_health_check.default.id
    initial_delay_sec = 300
  }
}

# Standalone VM Instance
resource "google_compute_instance" "standalone_vm" {
  name         = "standalone-admin-vm"
  machine_type = "e2-micro"
  zone         = var.zone

  boot_disk {
    initialize_params {
      image = "debian-cloud/debian-11"
    }
  }

  network_interface {
    network    = google_compute_network.vpc.id
    subnetwork = google_compute_subnetwork.subnet.id
    # No access_config block means no public IP (Uses Cloud NAT)
  }

  tags = ["admin-tool"]
}

# 6. Global Load Balancer
# Backend Service
resource "google_compute_backend_service" "default" {
  name                  = "web-backend-service"
  protocol              = "HTTP"
  port_name             = "http"
  load_balancing_scheme = "EXTERNAL"
  timeout_sec           = 10
  health_checks         = [google_compute_health_check.default.id]

  backend {
    group = google_compute_region_instance_group_manager.mig.instance_group
  }
}

# URL Map
resource "google_compute_url_map" "default" {
  name            = "web-url-map"
  default_service = google_compute_backend_service.default.id
}

# Target HTTP Proxy
resource "google_compute_target_http_proxy" "default" {
  name    = "web-http-proxy"
  url_map = google_compute_url_map.default.id
}

# Global Forwarding Rule
resource "google_compute_global_forwarding_rule" "default" {
  name                  = "web-forwarding-rule"
  ip_protocol           = "TCP"
  load_balancing_scheme = "EXTERNAL"
  port_range            = "80"
  target                = google_compute_target_http_proxy.default.id
}

# Outputs
output "load_balancer_ip" {
  value = google_compute_global_forwarding_rule.default.ip_address
}

response:
To provision this comprehensive GCP infrastructure, we will follow these logical steps:

1.  **Project & API Setup**: Define the provider and enable essential services like Compute Engine and the Network Management API.
2.  **Network Topology**: Create a custom Virtual Private Cloud (VPC) and a regional subnetwork.
3.  **External Access (Cloud NAT)**: Set up a Cloud Router and Cloud NAT gateway to allow instances without public IPs to access the internet for updates.
4.  **Security**: Configure firewall rules to allow traffic from the Google Load Balancer health checkers and IAP (Identity-Aware Proxy) for SSH.
5.  **Compute Resources**: Create an Instance Template (defining the OS and startup script), a Regional Managed Instance Group (MIG) for high availability, and a standalone VM instance as requested.
6.  **Global Load Balancer**: Define a Health Check, Backend Service (connected to the MIG), URL Map, Target HTTP Proxy, and a Global Forwarding Rule to expose the application to the internet.

```hcl
# --- Terraform Configuration for GCP Infrastructure ---

terraform {
  required_version = ">= 1.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

# Variables for customization
variable "project_id" {
  type        = string
  description = "The ID of the project to create/use"
}

variable "region" {
  type    = string
  default = "us-central1"
}

variable "zone" {
  type    = string
  default = "us-central1-a"
}

provider "google" {
  project = var.project_id
  region  = var.region
}

# 1. Project Services (APIs)
resource "google_project_service" "compute" {
  project = var.project_id
  service = "compute.googleapis.com"
  disable_on_destroy = false
}

# 2. Networking (VPC and Subnet)
resource "google_compute_network" "vpc" {
  name                    = "main-vpc"
  auto_create_subnetworks = false
  depends_on              = [google_project_service.compute]
}

resource "google_compute_subnetwork" "subnet" {
  name          = "main-subnet"
  ip_cidr_range = "10.0.1.0/24"
  region        = var.region
  network       = google_compute_network.vpc.id
}

# 3. Cloud NAT and Router (for private internet access)
resource "google_compute_router" "router" {
  name    = "nat-router"
  network = google_compute_network.vpc.id
  region  = var.region
}

resource "google_compute_router_nat" "nat" {
  name                               = "main-nat"
  router                             = google_compute_router.router.name
  region                             = var.region
  nat_ip_allocate_option             = "AUTO_ONLY"
  source_subnetwork_ip_ranges_to_nat = "ALL_SUBNETWORKS_ALL_IP_RANGES"
}

# 4. Firewall Rules
# Allow Health Checks and LB traffic (GCP ranges)
resource "google_compute_firewall" "allow_lb" {
  name    = "allow-lb-and-healthcheck"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["80"]
  }

  source_ranges = ["130.211.0.0/22", "35.191.0.0/16"]
  target_tags   = ["web-server"]
}

# Allow SSH via IAP
resource "google_compute_firewall" "allow_ssh" {
  name    = "allow-ssh-iap"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["35.235.240.0/20"]
}

# 5. Compute Resources
# Health Check for MIG and LB
resource "google_compute_health_check" "default" {
  name = "http-health-check"
  http_health_check {
    port = 80
  }
}

# Instance Template
resource "google_compute_instance_template" "tpl" {
  name         = "web-template"
  machine_type = "e2-medium"

  disk {
    source_image = "debian-cloud/debian-11"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network    = google_compute_network.vpc.id
    subnetwork = google_compute_subnetwork.subnet.id
  }

  metadata_startup_script = <<-EOT
    #!/bin/bash
    apt-get update
    apt-get install -y apache2
    echo "Hello from Terraform managed instance" > /var/www/html/index.html
  EOT

  tags = ["web-server"]
}

# Managed Instance Group
resource "google_compute_region_instance_group_manager" "mig" {
  name               = "web-mig"
  region             = var.region
  base_instance_name = "web-app"
  target_size        = 2

  version {
    instance_template = google_compute_instance_template.tpl.id
  }

  named_port {
    name = "http"
    port = 80
  }

  auto_healing_policies {
