}

# Standalone VM Instance
resource "google_compute_instance" "standalone_vm" {
  name         = "standalone-admin-vm"
  machine_type = "e2-micro"
  zone         = var.zone

  boot_disk {
    initialize_params {
      image = "debian-cloud/debian-11"
    }
  }

  network_interface {
    network    = google_compute_network.vpc.id
