# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC to associate the DHCP options with
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name        = "MainVPC"
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# 2. Define the DHCP Options Set
resource "aws_vpc_dhcp_options" "custom_dhcp" {
  domain_name          = "corp.example.com"
  domain_name_servers  = ["8.8.8.8", "8.8.4.4"] # Google DNS
  ntp_servers          = ["169.254.169.123"]    # Amazon Time Service
  netbios_name_servers = ["10.0.0.20"]          # Example NetBIOS Server
  netbios_node_type    = "2"                    # Node type: 2 (P-node: Point-to-point)

  tags = {
    Name        = "Custom-DHCP-Options"
    Environment = "Production"
    Project     = "Infrastructure"
  }
}

# 3. Associate the DHCP Options Set with the VPC
resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  vpc_id          = aws_vpc.main_vpc.id
  dhcp_options_id = aws_vpc_dhcp_options.custom_dhcp.id
}

# Outputs for verification
output "vpc_id" {
  value       = aws_vpc.main_vpc.id
  description = "The ID of the VPC"
}

output "dhcp_options_id" {
  value       = aws_vpc_dhcp_options.custom_dhcp.id
  description = "The ID of the DHCP options set"
}

reference:
# DHCP Options

## Set Terraform version constraint
terraform {
  required_version = "> 0.10.0"
}

data "aws_caller_identity" "current" {}

## Provisions DHCP options
resource "aws_vpc_dhcp_options" "dhcp" {
  domain_name          = var.domain_name
  domain_name_servers  = ["${compact(var.name_servers)}"]
  netbios_name_servers = ["${compact(var.netbios_name_servers)}"]
  netbios_node_type    = var.netbios_node_type
  ntp_servers          = ["${compact(var.ntp_servers)}"]

  tags {
    module_version = var.module_version
    application = var.stack_item_fullname
    account_id = data.aws_caller_identity.current.account_id
    caller_arn = data.aws_caller_identity.current.arn
    caller_id  = data.aws_caller_identity.current.user_id
    terraform  = "true"
    Name        = "${var.stack_item_label}-dhcp"
  }
}

resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  dhcp_options_id = aws_vpc_dhcp_options.dhcp.id
  vpc_id          = var.vpc_id
}


# Input Variables

## Resource Tags
variable "stack_item_fullname" {
  type        =  string
  description = "Long form descriptive name for this stack item. This value is used to create the 'application' resource tag for resources created by this stack item."
}

variable "stack_item_label" {
  type        = string
  description = "Short form identifier for this stack. This value is used to create the 'Name' resource tag for resources created by this stack item, and also serves as a unique key for re-use."
}

variable "module_version" {
  type        = string
  description = "Identifies the version of the terraform module used for this stack. This value is used to create the 'module_version' resource tag for resources created by this stack item."
}

## VPC parameters
variable "vpc_id" {
  type        = string
  description = "The ID of the VPC"
}

## DHCP parameters
variable "domain_name" {
  type        = string
  description = "The suffix domain name to use by default when resolving non Fully Qualified Domain Names"
  default     = ""
}

variable "name_servers" {
  type        = list
  description = "List of name servers to configure in '/etc/resolv.conf'"
  default     = ["AmazonProvidedDNS"]
}

variable "netbios_name_servers" {
  type        = list
  description = "List of NETBIOS name servers"
  default     = []
}

variable "netbios_node_type" {
  type        = string
  description = "The NetBIOS node type (1, 2, 4, or 8). AWS recommends to specify 2 since broadcast and multicast are not supported in their network."
  default     = ""
}

variable "ntp_servers" {
  type        = list
  description = "List of NTP servers to configure"
  default     = []
}


# Output variables

output "dhcp_id" {
  value = aws_vpc_dhcp_options.dhcp.id
}

response:
To configure AWS VPC DHCP options, we need to create two main resources: the `aws_vpc_dhcp_options` resource which defines the parameters, and the `aws_vpc_dhcp_options_association` resource which links those options to a specific VPC.

In the configuration below, we define the domain name, primary and secondary DNS (using Google Public DNS as placeholders), NTP servers, and NetBIOS node types commonly used in mixed-OS environments.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC to associate the DHCP options with
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name        = "MainVPC"
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# 2. Define the DHCP Options Set
resource "aws_vpc_dhcp_options" "custom_dhcp" {
  domain_name          = "corp.example.com"
  domain_name_servers  = ["8.8.8.8", "8.8.4.4"] # Google DNS
  ntp_servers          = ["169.254.169.123"]    # Amazon Time Service
  netbios_name_servers = ["10.0.0.20"]          # Example NetBIOS Server
  netbios_node_type    = "2"                    # Node type: 2 (P-node: Point-to-point)

  tags = {
    Name        = "Custom-DHCP-Options"
    Environment = "Production"
    Project     = "Infrastructure"
  }
}

# 3. Associate the DHCP Options Set with the VPC
resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  vpc_id          = aws_vpc.main_vpc.id
  dhcp_options_id = aws_vpc_dhcp_options.custom_dhcp.id
}

# Outputs for verification
output "vpc_id" {
  value       = aws_vpc.main_vpc.id
  description = "The ID of the VPC"
}

output "dhcp_options_id" {
  value       = aws_vpc_dhcp_options.custom_dhcp.id
  description = "The ID of the DHCP options set"
}
```

