# Configure the Google Cloud Provider
provider "google" {
  region = "us-central1"
}

# Variable for Organization ID
variable "org_id" {
  description = "The numeric Organization ID"
  type        = string
}

# Variable for Project ID where the Pub/Sub topic will reside
variable "project_id" {
  description = "The project ID to host the destination Pub/Sub topic"
  type        = string
}

# 1. Create the Pub/Sub Topic
resource "google_pubsub_topic" "logging_sink_topic" {
  name    = "org-logging-sink-topic"
  project = var.project_id
}

# 2. Create the Organization-level Logging Sink
resource "google_logging_organization_sink" "org_sink" {
  name             = "organization-audit-logs-sink"
  description      = "Routes specific organization logs to a Pub/Sub topic"
  org_id           = var.org_id

  # The destination includes the project and topic name
  destination      = "pubsub.googleapis.com/${google_pubsub_topic.logging_sink_topic.id}"

  # Example filter: capture all administrative logs
  filter           = "logName:"logs/cloudaudit.googleapis.com%2Factivity""

  # Include children projects/folders if desired
  include_children = true
}

# 3. IAM Binding: Allow the Sink's Writer Identity to publish to the topic
# This is required for the logs to actually flow into the topic.
resource "google_pubsub_topic_iam_member" "sink_publisher" {
  project = var.project_id
  topic   = google_pubsub_topic.logging_sink_topic.name
  role    = "roles/pubsub.publisher"
  member  = google_logging_organization_sink.org_sink.writer_identity
}

# Outputs
output "sink_name" {
  value       = google_logging_organization_sink.org_sink.name
  description = "The name of the organization logging sink."
}

output "topic_name" {
  value       = google_pubsub_topic.logging_sink_topic.name
  description = "The name of the Pub/Sub topic."
}

output "sink_writer_identity" {
  value       = google_logging_organization_sink.org_sink.writer_identity
  description = "The service account created for the sink to write to the destination."
}

response:
To provision an organization-level logging sink routing to a Pub/Sub topic, we must define the topic, the sink at the organization scope, and the critical IAM permissions that allow the Logging service's service account to publish to that topic.

Here is the complete Terraform configuration:

```hcl
# Configure the Google Cloud Provider
provider "google" {
  region = "us-central1"
}

# Variable for Organization ID
variable "org_id" {
  description = "The numeric Organization ID"
  type        = string
}

# Variable for Project ID where the Pub/Sub topic will reside
variable "project_id" {
  description = "The project ID to host the destination Pub/Sub topic"
  type        = string
}

# 1. Create the Pub/Sub Topic
resource "google_pubsub_topic" "logging_sink_topic" {
  name    = "org-logging-sink-topic"
  project = var.project_id
}

# 2. Create the Organization-level Logging Sink
resource "google_logging_organization_sink" "org_sink" {
  name             = "organization-audit-logs-sink"
  description      = "Routes specific organization logs to a Pub/Sub topic"
  org_id           = var.org_id

  # The destination includes the project and topic name
  destination      = "pubsub.googleapis.com/${google_pubsub_topic.logging_sink_topic.id}"

  # Example filter: capture all administrative logs
  filter           = "logName:"logs/cloudaudit.googleapis.com%2Factivity""

  # Include children projects/folders if desired
  include_children = true
}

# 3. IAM Binding: Allow the Sink's Writer Identity to publish to the topic
# This is required for the logs to actually flow into the topic.
resource "google_pubsub_topic_iam_member" "sink_publisher" {
  project = var.project_id
  topic   = google_pubsub_topic.logging_sink_topic.name
  role    = "roles/pubsub.publisher"
  member  = google_logging_organization_sink.org_sink.writer_identity
}

# Outputs
output "sink_name" {
  value       = google_logging_organization_sink.org_sink.name
  description = "The name of the organization logging sink."
}

output "topic_name" {
  value       = google_pubsub_topic.logging_sink_topic.name
  description = "The name of the Pub/Sub topic."
}

output "sink_writer_identity" {
  value       = google_logging_organization_sink.org_sink.writer_identity
  description = "The service account created for the sink to write to the destination."
}
```

