response:
To fulfill this request, we will use the `google_compute_ssl_certificate` resource. We will utilize the `random_id` resource to ensure uniqueness and apply the `lifecycle` block to enforce the `create_before_destroy` behavior, which is essential for SSL certificates to avoid downtime during renewals or replacements.

```hcl
# Configure the Google Cloud Provider
provider "google" {
  project = "your-project-id"
  region  = "us-central1"
}

# Generate a random suffix for the certificate name to ensure uniqueness
resource "random_id" "cert_suffix" {
  byte_length = 4
}

# Provision the SSL Certificate
resource "google_compute_ssl_certificate" "custom_ssl_cert" {
  # Concatenate a base name with the random hex suffix
  name        = "my-secure-cert-${random_id.cert_suffix.hex}"
  description = "A uniquely named managed SSL certificate with create-before-destroy logic"

  # The actual certificate and private key in PEM format
  # In a production scenario, these would likely be sourced from a Secret Manager or a local file
  certificate = file("path/to/certificate.crt")
  private_key = file("path/to/private.key")

  # Lifecycle policy to ensure the new certificate is created before the old one is deleted
  lifecycle {
    create_before_destroy = true
  }
}

# Output the generated name and certificate ID
output "certificate_name" {
  value       = google_compute_ssl_certificate.custom_ssl_cert.name
  description = "The unique name of the created SSL certificate"
}

output "certificate_id" {
  value       = google_compute_ssl_certificate.custom_ssl_cert.id
  description = "The ID of the created SSL certificate"
}
```

extracted_code:
# --- Providers Configuration ---

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
    digitalocean = {
      source  = "digitalocean/digitalocean"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "azurerm" {
  features {}
}

provider "digitalocean" {}

# --- Shared Configuration ---

locals {
  instance_name = "multi-cloud-node"
  ssh_key_name  = "deployer-key"
  public_key    = "ssh-rsa AAAAB3Nza...user@domain" # Replace with your actual public key
  user_data     = <<-EOF
              #!/bin/bash
              apt-get update
              apt-get install -y nginx
              echo "Hello from $(hostname) - Multi-Cloud setup" > /var/www/html/index.html
              systemctl enable nginx
              systemctl start nginx
              EOF
}

# --- AWS Resources ---

resource "aws_key_pair" "main" {
  key_name   = local.ssh_key_name
  public_key = local.public_key
}

resource "aws_security_group" "main" {
  name        = "allow_ssh_http"
  description = "Allow SSH and HTTP inbound traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "node" {
  ami                    = "ami-0c7217cdde317cfec" # Ubuntu 22.04 LTS
  instance_type          = "t3.micro"
  key_name               = aws_key_pair.main.key_name
  vpc_security_group_ids = [aws_security_group.main.id]
  user_data              = local.user_data

  tags = { Name = local.instance_name }
}

# --- Azure Resources ---

resource "azurerm_resource_group" "main" {
  name     = "multi-cloud-rg"
  location = "East US"
}

resource "azurerm_virtual_network" "main" {
  name                = "mc-vnet"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
}

resource "azurerm_subnet" "main" {
  name                 = "internal"
  resource_group_name  = azurerm_resource_group.main.name
  virtual_network_name = azurerm_virtual_network.main.name
  address_prefixes     = ["10.0.2.0/24"]
}

resource "azurerm_public_ip" "main" {
  name                = "mc-pip"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  allocation_method   = "Static"
}

resource "azurerm_network_security_group" "main" {
  name                = "mc-nsg"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  security_rule {
    name                       = "SSH"
    priority                   = 1001
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "22"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }

  security_rule {
    name                       = "HTTP"
    priority                   = 1002
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "80"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }
}

resource "azurerm_network_interface" "main" {
  name                = "mc-nic"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = azurerm_subnet.main.id
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id          = azurerm_public_ip.main.id
  }
}

resource "azurerm_network_interface_security_group_association" "main" {
  network_interface_id      = azurerm_network_interface.main.id
  network_security_group_id = azurerm_network_security_group.main.id
}

resource "azurerm_linux_virtual_machine" "node" {
  name                = local.instance_name
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  size                = "Standard_B1s"
  admin_username      = "adminuser"
  network_interface_ids = [
    azurerm_network_interface.main.id,
  ]

  admin_ssh_key {
    username   = "adminuser"
    public_key = local.public_key
  }

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Standard_LRS"
  }

  source_image_reference {
    publisher = "Canonical"
    offer     = "0001-com-ubuntu-server-jammy"
    sku       = "22_04-lts"
    version   = "latest"
  }

  user_data = base64encode(local.user_data)
}

# --- DigitalOcean Resources ---

resource "digitalocean_ssh_key" "main" {
  name       = local.ssh_key_name
  public_key = local.public_key
}

resource "digitalocean_firewall" "main" {
  name = "mc-firewall"

  droplet_ids = [digitalocean_droplet.node.id]

  inbound_rule {
    protocol         = "tcp"
    port_range       = "22"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  inbound_rule {
    protocol         = "tcp"
    port_range       = "80"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  outbound_rule {
    protocol              = "tcp"
    port_range            = "1-65535"
    destination_addresses = ["0.0.0.0/0", "::/0"]
  }
}

resource "digitalocean_droplet" "node" {
  image     = "ubuntu-22-04-x64"
  name      = local.instance_name
  region    = "nyc1"
  size      = "s-1vcpu-1gb"
  ssh_keys  = [digitalocean_ssh_key.main.fingerprint]
  user_data = local.user_data
}

# --- AWS Route 53 DNS Record ---

data "aws_route53_zone" "selected" {
  name         = "example.com." # Replace with your managed domain
  private_zone = false
}

resource "aws_route53_record" "multi_cloud" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "nodes.${data.aws_route53_zone.selected.name}"
  type    = "A"
  ttl     = "300"
  records = [
    aws_instance.node.public_ip,
    azurerm_public_ip.main.ip_address,
    digitalocean_droplet.node.ipv4_address
  ]
}

