provider "azure" {
  settings_file = var.azure_settings_file
}

resource "azure_instance" "server" {
  name                 = "russ-terraform-test"
  hosted_service_name  = var.hosted_service
  image                = "OpenLogic 7.1"
  size                 = "Basic_A1"
  storage_service_name = var.storage_service
  location             = "West Europe"
  username             = var.azure_username
  ssh_key_thumbprint   = var.azure_ssh_key_thumbprint

  endpoint {
    name        = "SSH"
    protocol    = "tcp"
    public_port = 22
    private_port = 22
  }

  endpoint {
    name        = "WEB"
    protocol    = "tcp"
    public_port = 80
    private_port = 80
  }

  connection {
    user     = var.azure_username
    type     = "ssh"
    key_file = var.pvt_key
    timeout  = "2m"
    agent    = false
  }

  provisioner "file" {
    source      = "script.sh"
    destination = "/tmp/script.sh"
  }

  provisioner "remote-exec" {
    inline = ["bash /tmp/script.sh"]
  }
}

provider "digitalocean" {
  token = var.do_token
}

resource "digitalocean_droplet" "server" {
  image        = "centos-7-0-x64"
  name         = var.server_name
  region       = "nyc2"
  size         = "512mb"
  ssh_keys     = [var.do_ssh_fingerprint]

  connection {
    user     = "root"
    type     = "ssh"
    key_file = var.pvt_key
    timeout  = "2m"
    agent    = false
  }

  provisioner "file" {
    source      = "script.sh"
    destination = "/tmp/script.sh"
  }

  provisioner "remote-exec" {
    inline = ["bash /tmp/script.sh"]
  }
}

provider "aws" {
  access_key = var.aws_access_key
  secret_key = var.aws_secret_key
  region     = "us-east-1"
}

resource "aws_instance" "server" {
  ami             = "ami-96a818fe"
  instance_type   = "t2.micro"
  subnet_id       = var.aws_subnet_id
  security_groups = [aws_security_group.web.id, aws_security_group.ssh.id, aws_security_group.all_outgoing.id]
  key_name        = var.aws_key_name

  connection {
    user     = "centos"
    type     = "ssh"
    key_file = var.pvt_key
    timeout  = "2m"
    agent    = false
  }

  provisioner "file" {
    source      = "script.sh"
    destination = "/tmp/script.sh"
  }

  provisioner "remote-exec" {
    inline = ["bash /tmp/script.sh"]
  }

  tags = {
    Name = var.server_name
  }
}

resource "aws_security_group" "web" {
  name        = "web"
  description = "Allow all web traffic"
  vpc_id      = var.aws_vpc

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web"
  }
}

resource "aws_security_group" "ssh" {
  name        = "ssh"
  description = "Allow all ssh traffic"
  vpc_id      = var.aws_vpc

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ssh"
  }
}

resource "aws_security_group" "all_outgoing" {
  name        = "all_outgoing"
  description = "Allow all outgoing traffic"
  vpc_id      = var.aws_vpc

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "all_outgoing"
  }
}

resource "aws_route53_record" "testing" {
  zone_id = var.aws_hosted_zone_id
  name    = var.fqdn
  type    = "A"
  ttl     = 300
  records = [aws_instance.server.public_ip, azure_instance.server.vip_address, digitalocean_droplet.server.ipv4_address]
}

response:
To achieve this multi-cloud setup, we will configure the AWS, Azure, and DigitalOcean providers. The configuration includes defining local variables for common settings (like the startup script), creating security groups/firewalls for each cloud to allow SSH and HTTP, provisioning the instances, and finally creating Route 53 A records for each instance's public IP.

```hcl
# --- Providers Configuration ---

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
    digitalocean = {
      source  = "digitalocean/digitalocean"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "azurerm" {
  features {}
}

provider "digitalocean" {}

# --- Shared Configuration ---

locals {
  instance_name = "multi-cloud-node"
  ssh_key_name  = "deployer-key"
  public_key    = "ssh-rsa AAAAB3Nza...user@domain" # Replace with your actual public key
  user_data     = <<-EOF
              #!/bin/bash
              apt-get update
              apt-get install -y nginx
              echo "Hello from $(hostname) - Multi-Cloud setup" > /var/www/html/index.html
              systemctl enable nginx
              systemctl start nginx
              EOF
}

# --- AWS Resources ---

resource "aws_key_pair" "main" {
  key_name   = local.ssh_key_name
  public_key = local.public_key
}

resource "aws_security_group" "main" {
  name        = "allow_ssh_http"
  description = "Allow SSH and HTTP inbound traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "node" {
  ami                    = "ami-0c7217cdde317cfec" # Ubuntu 22.04 LTS
  instance_type          = "t3.micro"
  key_name               = aws_key_pair.main.key_name
  vpc_security_group_ids = [aws_security_group.main.id]
  user_data              = local.user_data

  tags = { Name = local.instance_name }
}

# --- Azure Resources ---

resource "azurerm_resource_group" "main" {
  name     = "multi-cloud-rg"
  location = "East US"
}

resource "azurerm_virtual_network" "main" {
  name                = "mc-vnet"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
}

resource "azurerm_subnet" "main" {
  name                 = "internal"
  resource_group_name  = azurerm_resource_group.main.name
  virtual_network_name = azurerm_virtual_network.main.name
  address_prefixes     = ["10.0.2.0/24"]
}

resource "azurerm_public_ip" "main" {
  name                = "mc-pip"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  allocation_method   = "Static"
}

resource "azurerm_network_security_group" "main" {
  name                = "mc-nsg"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  security_rule {
    name                       = "SSH"
    priority                   = 1001
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "22"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }

  security_rule {
    name                       = "HTTP"
    priority                   = 1002
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "80"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }
}

resource "azurerm_network_interface" "main" {
  name                = "mc-nic"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = azurerm_subnet.main.id
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id          = azurerm_public_ip.main.id
  }
}

resource "azurerm_network_interface_security_group_association" "main" {
  network_interface_id      = azurerm_network_interface.main.id
  network_security_group_id = azurerm_network_security_group.main.id
}

resource "azurerm_linux_virtual_machine" "node" {
  name                = local.instance_name
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  size                = "Standard_B1s"
  admin_username      = "adminuser"
  network_interface_ids = [
    azurerm_network_interface.main.id,
  ]

  admin_ssh_key {
    username   = "adminuser"
    public_key = local.public_key
  }

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Standard_LRS"
  }

  source_image_reference {
    publisher = "Canonical"
    offer     = "0001-com-ubuntu-server-jammy"
    sku       = "22_04-lts"
    version   = "latest"
  }

  user_data = base64encode(local.user_data)
}

# --- DigitalOcean Resources ---

resource "digitalocean_ssh_key" "main" {
  name       = local.ssh_key_name
  public_key = local.public_key
}

resource "digitalocean_firewall" "main" {
  name = "mc-firewall"

  droplet_ids = [digitalocean_droplet.node.id]

  inbound_rule {
    protocol         = "tcp"
    port_range       = "22"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  inbound_rule {
    protocol         = "tcp"
    port_range       = "80"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  outbound_rule {
    protocol              = "tcp"
    port_range            = "1-65535"
    destination_addresses = ["0.0.0.0/0", "::/0"]
  }
}

resource "digitalocean_droplet" "node" {
  image     = "ubuntu-22-04-x64"
  name      = local.instance_name
  region    = "nyc1"
  size      = "s-1vcpu-1gb"
  ssh_keys  = [digitalocean_ssh_key.main.fingerprint]
  user_data = local.user_data
}

# --- AWS Route 53 DNS Record ---

data "aws_route53_zone" "selected" {
  name         = "example.com." # Replace with your managed domain
  private_zone = false
}

resource "aws_route53_record" "multi_cloud" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "nodes.${data.aws_route53_zone.selected.name}"
  type    = "A"
  ttl     = "300"
  records = [
    aws_instance.node.public_ip,
    azurerm_public_ip.main.ip_address,
    digitalocean_droplet.node.ipv4_address
  ]
}
```

