terraform {
    required_version = ">= 0.13"

    required_providers {
        aws = {
            source = "hashicorp/aws"
        }
    }
}


variable "bucket" {
    type = string
    description = "bucket where deployment package and images are stored"
}

variable "bucket_region" {
    type = string
    description = "the region where the bucket resides"
}

variable "container_image_uri" {
    type = string
    description = "ECR container image URI"
}

variable "photos_prefix" {
    type = string
    description = "prefix in bucket where images are stored"
}

variable "api_gateway_exec_arn" {
    type = string
    description = "full execution arn for the api gateway"
}

locals {
    fn_name = "thumbor"
}


data "aws_iam_policy_document" "assume" {
    statement {
        actions = ["sts:AssumeRole"]

        principals {
            type = "Service"
            identifiers = ["lambda.amazonaws.com"]
        }
    }
}

data "aws_iam_policy_document" "exec" {
    statement {
        sid = "getdemphotos"

        actions = [
            "s3:GetObject",
        ]

        resources = [
            "arn:aws:s3:::${var.bucket}/${var.photos_prefix}/*",
        ]
    }

    ## allow logging
    statement {
        sid = "loggit"

        actions = [
            "logs:PutLogEvents",
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
        ]

        resources = ["*"]
    }
}

resource "aws_iam_role" "lambda" {
    path = "/service-role/"
    name = "LambdaThumbor"
    description = "Permissions for the ${local.fn_name} function"
    assume_role_policy = data.aws_iam_policy_document.assume.json
}

resource "aws_iam_role_policy" "lambda" {
    name = aws_iam_role.lambda.name
    role = aws_iam_role.lambda.id
    policy = data.aws_iam_policy_document.exec.json
}


resource "aws_lambda_function" "fn" {
    function_name = local.fn_name

    role = aws_iam_role.lambda.arn

    package_type = "Image"
    image_uri = var.container_image_uri

    memory_size = 1536
    timeout = 10

    environment {
        variables = {
            ENABLE_CORS = "no"
            LOG_LEVEL = "INFO"

            SEND_ANONYMOUS_DATA = "Hell no"

            RESPECT_ORIENTATION = "True"

            TC_AWS_ENDPOINT = "https://s3.amazonaws.com"
            TC_AWS_REGION = var.bucket_region
            TC_AWS_LOADER_BUCKET = var.bucket
            TC_AWS_LOADER_ROOT_PATH = var.photos_prefix
        }
    }
}

resource "aws_lambda_permission" "api_gateway" {
    statement_id = "AllowAPIGatewayInvoke"
    action = "lambda:InvokeFunction"
    function_name = aws_lambda_function.fn.function_name
    principal = "apigateway.amazonaws.com"

    source_arn = var.api_gateway_exec_arn
}


output "invoke_arn" {
    value = aws_lambda_function.fn.invoke_arn
}

response:
To provision an AWS Lambda function from a container image with the necessary IAM roles and API Gateway permissions, we need to define the IAM execution role, the Lambda function itself (pointing to an ECR image or defined package), and the specific `lambda_permission` resource. 

Note: While the request mentions a "container image located in an S3 bucket", in AWS, container images are pulled from **Amazon ECR**. If the image is currently in S3 as a `.zip` file, it is a standard deployment; if it is a Docker image, it must reside in ECR. I will provide the configuration for a **Container Image Lambda** using ECR, as that is the standard architecture for containerized functions.

```hcl
# Terraform Configuration for Container-based Lambda with API Gateway Permissions

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_exec_role" {
  name = "container_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach basic execution policy (CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Reference to the Container Image in ECR
# Replace '123456789012.dkr.ecr.us-east-1.amazonaws.com/my-repo:latest' with your actual URI
resource "aws_lambda_function" "container_lambda" {
  function_name    = "my-container-lambda"
  role             = aws_iam_role.lambda_exec_role.arn
  package_type     = "Image"
  image_uri        = "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-image-repo:v1"

  timeout          = 30
  memory_size      = 512

  environment {
    variables = {
      ENV = "production"
    }
  }
}

# 4. API Gateway Permission to Invoke Lambda
# This allows a specific API Gateway (rest_api or http_api) to trigger the function
resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.container_lambda.function_name
  principal     = "apigateway.amazonaws.com"

  # The source_arn is optional but recommended for security. 
  # It restricts invocation to a specific API Gateway stage/resource.
  # Replace with your API Gateway ARN if available.
  # source_arn = "arn:aws:execute-api:us-east-1:123456789012:api-id/*/*/*"
}

# Output the Lambda ARN
output "lambda_function_arn" {
  value = aws_lambda_function.container_lambda.arn
}
```

