  default = 1
}
variable "lbs" {
  default = 2
}
variable "masters" {
  default = 3
}
variable "slaves" {
  default = 3
}

module "adminlb" {
  source                    = "./modules/adminlb"
  security_group_http       = aws_security_group.mesos_http_admin.id
  security_group_ssh        = aws_security_group.mesos_ssh.id
  security_group_internal   = aws_security_group.mesos_internal.id
  discovery_instance_profile = var.discovery_instance_profile
  count                     = var.adminlbs
  instance_type             = var.adminlb_instance_type
  subnet_ids                = var.public_subnet_ids
  admin_key_name            = var.admin_key_name
  domain                    = var.domain
  region                    = var.region
}

module "dns" {
  source               = "./modules/dns"
  domain               = var.domain
  elb_name             = module.elb.dns_name
  adminlb_public_ips   = module.adminlb.public_ips
}

module "elb" {
  source               = "./modules/elb"
  instance_ids         = module.lb.instance_ids
  subnet_ids           = var.public_subnet_ids
  security_group_ids   = aws_security_group.mesos_http_all.id
}

resource "aws_security_group" "mesos_internal" {
  name        = "mesos-${var.domain}-internal_allow_all"
  description = "Allow all inbound traffic"
  vpc_id      = var.vpc_id
  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "-1"
    self        = true
  }

  tags = {
    Name = "mesos-${var.domain}-internal_allow_all"
  }
}

resource "aws_security_group" "mesos_http_all" {
  name        = "mesos-${var.domain}-http_all"
  description = "Allow all inbound HTTP traffic"
  vpc_id      = var.vpc_id
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mesos-${var.domain}-http_all"
  }
}

resource "aws_security_group" "mesos_http_admin" {
  name        = "mesos-${var.domain}-http_admin"
  description = "Allow inbound HTTP traffic from admin IP range"
  vpc_id      = var.vpc_id
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [var.admin_iprange]
  }

  tags = {
    Name = "mesos-${var.domain}-http_admin"
  }
}

resource "aws_security_group" "mesos_ssh" {
  name        = "mesos-${var.domain}-ssh"
  description = "Allow all inbound SSH traffic"
  vpc_id      = var.vpc_id
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = [var.admin_iprange, var.vpc_iprange]
  }

  tags = {
    Name = "mesos-${var.domain}-ssh"
  }
}

module "lb" {
  source                  = "./modules/lb"
  security_group_http     = aws_security_group.mesos_http_all.id
  security_group_ssh      = aws_security_group.mesos_ssh.id
  security_group_internal = aws_security_group.mesos_internal.id
  subnet_ids              = var.private_subnet_ids
  discovery_instance_profile = var.discovery_instance_profile
  count                   = var.lbs
  instance_type           = var.lb_instance_type
  admin_key_name          = var.admin_key_name
  domain                  = var.domain
  region                  = var.region
}

module "mesos_master" {
  source                  = "./modules/mesos_master"
  security_group_ssh      = aws_security_group.mesos_ssh.id
  security_group_internal = aws_security_group.mesos_internal.id
  discovery_instance_profile = var.discovery_instance_profile
  subnet_ids              = var.private_subnet_ids
  count                   = var.masters
  instance_type           = var.master_instance_type
  admin_key_name          = var.admin_key_name
  region                  = var.region
}

module "mesos_slave" {
  source                  = "./modules/mesos_slave"
  discovery_instance_profile = var.discovery_instance_profile
  count                   = var.slaves
  instance_type           = var.slave_instance_type
  subnet_ids              = var.private_subnet_ids
  security_group_ssh      = aws_security_group.mesos_ssh.id
  security_group_internal = aws_security_group.mesos_internal.id
  admin_key_name          = var.admin_key_name
  zookeeper_cluster_size  = var.masters
  region                  = var.region
}

output "mesos_elb_dns_name" {
  value = module.elb.dns_name
}

output "mesos_elb_id" {
  value = module.elb.id
}

output "marathon_api" {
  value = "http://marathon.admin.${var.domain}"
}

output "mesos_api" {
  value = "http://mesos.admin.${var.domain}"
}

output "domain" {
  value = var.domain
}

response:
To provision a Mesos cluster (often used with frameworks like DC/OS or Marathon) on AWS, we must define the VPC networking, security groups for internal communication (Zookeeper/Mesos/Marathon ports), and the EC2 instances for Masters and Slaves. We will also include Public and Internal Load Balancers to handle administrative and application traffic.

The following Terraform configuration defines these components in a unified structure.

```hcl
# Define Provider and Variables
provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  default = "us-east-1"
}

variable "vpc_cidr" {
  default = "10.0.0.0/16"
}

variable "instance_types" {
  type = map(string)
  default = {
    master = "m5.xlarge"
    slave  = "m5.2xlarge"
    lb     = "t3.medium"
  }
}

variable "counts" {
  type = map(number)
  default = {
    master = 3
    slave  = 5
  }
}

# 1. Networking - VPC and Subnets
resource "aws_vpc" "mesos_vpc" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  tags                 = { Name = "mesos-vpc" }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.mesos_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "${var.aws_region}a"
  tags                    = { Name = "mesos-public-subnet" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.mesos_vpc.id
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.mesos_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}

# 2. Security Groups
resource "aws_security_group" "mesos_common" {
  name        = "mesos-common-sg"
  description = "Internal cluster communication"
  vpc_id      = aws_vpc.mesos_vpc.id

  # Allow all internal traffic within the group
  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  # SSH Access
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Load Balancers
# Admin Load Balancer (for Mesos/Marathon UI)
resource "aws_lb" "admin_lb" {
  name               = "mesos-admin-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.mesos_common.id]
  subnets            = [aws_subnet.public.id]
}

resource "aws_lb_target_group" "mesos_master_tg" {
  name     = "mesos-master-tg"
  port     = 5050
  protocol = "HTTP"
  vpc_id   = aws_vpc.mesos_vpc.id
}

# Public App Load Balancer
resource "aws_lb" "app_lb" {
  name               = "mesos-app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.mesos_common.id]
  subnets            = [aws_subnet.public.id]
}

# 4. EC2 Instances
data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["099720109477"] # Canonical
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }
}

# Master Nodes
resource "aws_instance" "mesos_master" {
  count                  = var.counts["master"]
  ami                    = data.aws_ami.ubuntu.id
  instance_type          = var.instance_types["master"]
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.mesos_common.id]

  tags = {
    Name = "mesos-master-${count.index}"
    Role = "master"
  }
}

# Slave Nodes
resource "aws_instance" "mesos_slave" {
  count                  = var.counts["slave"]
  ami                    = data.aws_ami.ubuntu.id
  instance_type          = var.instance_types["slave"]
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.mesos_common.id]

  tags = {
    Name = "mesos-slave-${count.index}"
    Role = "slave"
  }
}

# 5. DNS (Route53 Private Zone)
resource "aws_route53_zone" "internal" {
  name = "mesos.local"
  vpc {
    vpc_id = aws_vpc.mesos_vpc.id
  }
}

resource "aws_route53_record" "master_nodes" {
  count   = var.counts["master"]
  zone_id = aws_route53_zone.internal.zone_id
  name    = "master-${count.index}.mesos.local"
  type    = "A"
  ttl     = "300"
  records = [aws_instance.mesos_master[count.index].private_ip]
}

# Attach masters to Admin LB Target Group
resource "aws_lb_target_group_attachment" "master_attachment" {
  count            = var.counts["master"]
  target_group_arn = aws_lb_target_group.mesos_master_tg.arn
  target_id        = aws_instance.mesos_master[count.index].id
  port             = 5050
}

# Outputs
output "admin_lb_dns" {
  value = aws_lb.admin_lb.dns_name
}

output "app_lb_dns" {
  value = aws_lb.app_lb.dns_name
}

output "master_ips" {
  value = aws_instance.mesos_master[*].public_ip
}
