# Configure the Google Cloud Provider
provider "google" {
  project = var.project_id
  region  = var.region
  zone    = var.zone
}

# Variables for customization
variable "project_id" {
  description = "The GCP Project ID"
  type        = string
}

variable "region" {
  description = "The target region"
  type        = string
  default     = "us-central1"
}

variable "zone" {
  description = "The target zone"
  type        = string
  default     = "us-central1-a"
}

variable "network_name" {
  description = "The name of the existing VPC network"
  type        = string
  default     = "default"
}

variable "instance_names" {
  description = "A list of names for the virtual machines"
  type        = list(string)
  default     = ["web-server-01", "web-server-02"]
}

variable "machine_type" {
  description = "Machine type if not fully defined by template"
  type        = string
  default     = "e2-medium"
}

# 1. Define an Instance Template
resource "google_compute_instance_template" "tpl" {
  name         = "standard-instance-template"
  machine_type = var.machine_type

  disk {
    source_image = "debian-cloud/debian-11"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network = var.network_name
    # Including access_config (even empty) ensures a public IP is assigned
    access_config {
      network_tier = "PREMIUM"
    }
  }

  metadata = {
    foo = "bar"
  }
}

# 2. Provision Virtual Machines from the Template
resource "google_compute_instance_from_template" "vm_instances" {
  for_each = toset(var.instance_names)

  name = each.value
  zone = var.zone

  source_instance_template = google_compute_instance_template.tpl.id

  # Overriding the network interface to ensure specific network attachment
  # while inheriting the public IP capability from the template
  network_interface {
    network = var.network_name
    access_config {
      # Leaving this block enables a dynamic Ephemeral Public IP
    }
  }
}

# 3. Output detailed per-instance data
output "instance_details" {
  description = "Detailed information for each provisioned instance"
  value = {
    for name, instance in google_compute_instance_from_template.vm_instances : name => {
      hostname   = instance.name
      private_ip = instance.network_interface[0].network_ip
      public_ip  = instance.network_interface[0].access_config[0].nat_ip
    }
  }
}

