    }
  }

  metadata = {
    foo = "bar"
  }
}

# 2. Provision Virtual Machines from the Template
resource "google_compute_instance_from_template" "vm_instances" {
  for_each = toset(var.instance_names)

  name = each.value
  zone = var.zone

  source_instance_template = google_compute_instance_template.tpl.id

  # Overriding the network interface to ensure specific network attachment
  # while inheriting the public IP capability from the template
  network_interface {
    network = var.network_name
    access_config {
      # Leaving this block enables a dynamic Ephemeral Public IP
    }
  }
}

# 3. Output detailed per-instance data
output "instance_details" {
