# Shared Terraform Configuration for CentOS 7 Instances on AWS

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration with credentials
provider "aws" {
  region     = "us-west-2"
  access_key = var.aws_access_key
  secret_key = var.aws_secret_key
}

# Variables for customization
variable "aws_access_key" {
  description = "AWS Access Key"
  type        = string
  sensitive   = true
}

variable "aws_secret_key" {
  description = "AWS Secret Key"
  type        = string
  sensitive   = true
}

variable "instance_count" {
  description = "Number of EC2 instances to create"
  type        = number
  default     = 1
}

variable "associate_eip" {
  description = "Boolean to decide if Elastic IPs should be associated"
  type        = bool
  default     = false
}

variable "ssh_key_name" {
  description = "Name of the existing AWS SSH Key Pair"
  type        = string
}

variable "user_data_script" {
  description = "The shell script content for user_data"
  type        = string
  default     = "#!/bin/bash
echo 'Hello World' > /tmp/hello.txt"
}

variable "instance_type" {
  description = "EC2 Instance type"
  type        = string
  default     = "t2.micro"
}

# Data source to find the latest CentOS 7 AMI
data "aws_ami" "centos7" {
  most_recent = true
  owners      = ["679593333241"] # Official CentOS owner ID

  filter {
    name   = "name"
    values = ["CentOS-7-2111-*"] # Matches the latest CentOS 7 x86_64 builds
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
}

# EC2 Instance Resource
resource "aws_instance" "this" {
  count         = var.instance_count
  ami           = data.aws_ami.centos7.id
  instance_type = var.instance_type
  key_name      = var.ssh_key_name
  user_data     = var.user_data_script

  tags = {
    Name        = "CentOS7-Instance-${count.index + 1}"
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Optional Elastic IP Resource
resource "aws_eip" "this" {
  count    = var.associate_eip ? var.instance_count : 0
  instance = aws_instance.this[count.index].id
  domain   = "vpc"

  tags = {
    Name = "EIP-CentOS7-${count.index + 1}"
  }
}

# Outputs to retrieve connection info
output "instance_public_ips" {
  value       = var.associate_eip ? aws_eip.this[*].public_ip : aws_instance.this[*].public_ip
  description = "The public IP addresses of the instances"
}

