provider "aws" {
  region     = var.region
  access_key = var.access_key
  secret_key = var.secret_key
}

resource "aws_instance" "appserver_node" {
  count               = var.servers
  ami                 = var.ami_id
  availability_zone   = element(var.azs, count.index)
  key_name            = var.key_name
  instance_type       = var.instance_type
  user_data           = var.user_data
  subnet_id           = var.subnet_id

  tags = {
    Name       = "${var.prefix}-node-${count.index}"
    created_by = var.tags["created_by"]
  }

  root_block_device {
    delete_on_termination = true
  }
}

resource "aws_eip" "appserver_eip" {
  count     = var.create_eip ? var.servers : 0
  instance  = element(aws_instance.appserver_node.*.id, count.index)
}

# AWS Provider Variables
variable "region" {
  default     = "us-west-2"
  description = "The region of AWS"
}

variable "access_key" {}
variable "secret_key" {}

# Instance Variables
variable "ami_id" {
  default     = "ami-d2c924b2"  # Please replace with actual CentOS 7 AMI ID if it's different
  description = "The ID of the AMI to use"
}

variable "azs" {
  type        = list(string)
  default     = ["us-west-2a"]
  description = "A list of availability zones in the region for your instances"
}

variable "subnet_id" {
  description = "The VPC subnet the instance(s) will go in"
}

variable "key_name" {
  description = "The name of the AWS keypair to access the instance"
}

variable "instance_type" {
  default     = "t2.micro"
  description = "The instance type you wish to launch"
