# Configure the GCP Provider
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  region = "us-central1"
}

# 1. Project Creation
resource "google_project" "network_project" {
  name       = "net-hub-prod"
  project_id = "net-hub-${random_id.suffix.hex}"
  org_id     = var.org_id
}

resource "google_project" "data_project" {
  name       = "data-workload-prod"
  project_id = "data-workload-${random_id.suffix.hex}"
  org_id     = var.org_id
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. Networking (VPC and Subnets)
resource "google_compute_network" "vpc" {
  project                 = google_project.network_project.project_id
  name                    = "hardened-vpc"
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "trusted_subnetwork" {
  project       = google_project.network_project.project_id
  name          = "private-subnet"
  ip_cidr_range = "10.0.1.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc.id
  # Enforce Private Google Access for data exfiltration prevention
  private_ip_google_access = true
}

# 3. Organization Policies (Hardening)
resource "google_project_organization_policy" "no_external_ips" {
  project    = google_project.network_project.project_id
  constraint = "constraints/compute.vmExternalIpAccess"
  list_policy {
    deny {
      all = true
    }
  }
}

resource "google_project_organization_policy" "restrict_vpc_peering" {
  project    = google_project.data_project.project_id
  constraint = "constraints/compute.restrictVpcPeering"
  list_policy {
    deny {
      all = true
    }
  }
}

# 4. Bastion Host (No External IP)
resource "google_compute_instance" "bastion" {
  project      = google_project.network_project.project_id
  name         = "bastion-vm"
  machine_type = "e2-medium"
  zone         = "us-central1-a"

  boot_disk {
    initialize_params {
      image = "debian-cloud/debian-11"
    }
  }

  network_interface {
    subnetwork = google_compute_subnetwork.trusted_subnetwork.id
    # No access_config block means no external IP
  }

  metadata = {
    block-project-ssh-keys = "true"
  }

  service_account {
    scopes = ["cloud-platform"]
  }
}

# 5. Data Resources (BigQuery & Storage)
resource "google_bigquery_dataset" "secure_dataset" {
  project    = google_project.data_project.project_id
  dataset_id = "sensitive_data_store"
  location   = "US"
}

resource "google_storage_bucket" "secure_bucket" {
  project                     = google_project.data_project.project_id
  name                        = "hardened-storage-${random_id.suffix.hex}"
  location                    = "US"
  force_destroy               = true
  uniform_bucket_level_access = true

  versioning {
    enabled = true
  }
}

# 6. VPC Service Controls (Data Exfiltration Prevention)
resource "google_access_context_manager_access_policy" "default_policy" {
  parent = "organizations/${var.org_id}"
  title  = "Default Security Policy"
}

resource "google_access_context_manager_service_perimeter" "data_perimeter" {
  parent = "accessPolicies/${google_access_context_manager_access_policy.default_policy.name}"
  name   = "accessPolicies/${google_access_context_manager_access_policy.default_policy.name}/servicePerimeters/data_perimeter"
  title  = "Data_Exfiltration_Perimeter"

  status {
    restricted_services = [
      "storage.googleapis.com",
      "bigquery.googleapis.com"
    ]

    projects = [
      "projects/${google_project.data_project.number}",
      "projects/${google_project.network_project.number}"
    ]

    # Allows the VPC to communicate with restricted services
    vpc_accessible_services {
      enable_restriction = true
      allowed_services   = ["RESTRICTED-SERVICES"]
    }
  }
}

# 7. Cloud NAT (Required for the Bastion to get updates without External IP)
resource "google_compute_router" "router" {
  name    = "nat-router"
  project = google_project.network_project.project_id
  region  = "us-central1"
  network = google_compute_network.vpc.id
}

resource "google_compute_router_nat" "nat" {
  name                               = "nat-config"
  project                            = google_project.network_project.project_id
  router                             = google_compute_router.router.name
  region                             = "us-central1"
  nat_ip_allocate_option             = "AUTO_ONLY"
  source_subnetwork_ip_ranges_to_nat = "ALL_SUBNETWORKS_ALL_IP_RANGES"
}

# Variables
variable "org_id" {
  description = "The numeric Organization ID in GCP"
  type        = string
}

