# Terraform configuration for Google Kubernetes Engine (GKE)

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "cluster_name" {
  description = "The name of the GKE cluster"
  type        = string
  default     = "primary-gke-cluster"
}

variable "region" {
  description = "The region or zone to host the cluster in"
  type        = string
  default     = "us-central1"
}

variable "description" {
  description = "A description of the cluster"
  type        = string
  default     = "Managed GKE cluster provisioned by Terraform"
}

variable "network" {
  description = "The VPC network to host the cluster in"
  type        = string
}

variable "subnetwork" {
  description = "The subnetwork to host the cluster in"
  type        = string
}

variable "node_count" {
  description = "The initial number of nodes per zone"
  type        = number
  default     = 3
}

variable "machine_type" {
  description = "The machine type for the nodes"
  type        = string
  default     = "e2-medium"
}

variable "service_account_email" {
  description = "The service account to be used by the node VMs"
  type        = string
}

# GKE Cluster Definition
resource "google_container_cluster" "primary" {
  name        = var.cluster_name
  location    = var.region
  description = var.description
  project     = var.project_id

  network    = var.network
  subnetwork = var.subnetwork

  # We're using a separately managed node pool, so we delete the default pool
  remove_default_node_pool = true
  initial_node_count       = 1

  # Required IP Allocation Policy for Alias IPs (VPC-native cluster)
  ip_allocation_policy {
    cluster_ipv4_cidr_block  = ""
    services_ipv4_cidr_block = ""
  }

  # Setting networking mode to VPC_NATIVE is recommended
  networking_mode = "VPC_NATIVE"
}

# Separately Managed Node Pool
resource "google_container_node_pool" "primary_nodes" {
  name       = "${var.cluster_name}-node-pool"
  location   = var.region
  cluster    = google_container_cluster.primary.name
  node_count = var.node_count
  project    = var.project_id

  node_config {
    machine_type    = var.machine_type
    service_account = var.service_account_email

    # OAuth Scopes for logging, monitoring, and full cloud platform access
    oauth_scopes = [
      "https://www.googleapis.com/auth/logging.write",
      "https://www.googleapis.com/auth/monitoring",
      "https://www.googleapis.com/auth/cloud-platform"
    ]

    labels = {
      env = "production"
    }

    tags = ["gke-node", var.cluster_name]
  }
}

output "cluster_endpoint" {
  description = "The IP address of the cluster master"
  value       = google_container_cluster.primary.endpoint
}

output "cluster_name" {
  description = "The name of the GKE cluster"
  value       = google_container_cluster.primary.name
}

