reference:
# Variables
variable "name" {
  description = "The name prefix for resources"
}

variable "environment" {
  description = "The deployment environment (e.g., dev, staging, prod)"
}

# IAM Role
resource "aws_iam_role" "iam_role" {
  name               = "${var.name}-${var.environment}"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [
      {
        Action    = "sts:AssumeRole",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "instance_profile" {
  name  = "${var.name}-${var.environment}"
  path  = "/"
  roles = [aws_iam_role.iam_role.name]
}

response:
To provision an EC2 IAM role and instance profile, we need to define three primary resources: the IAM Role itself, an "Assume Role Policy" that allows EC2 services to use the role, and an Instance Profile which acts as a container for the role when attaching it to an EC2 instance.

The following configuration utilizes variables for the naming prefix and environment to ensure the resources are modular and follow a consistent naming convention.

```hcl
# --- Variables ---
variable "naming_prefix" {
  description = "A prefix to prepend to resource names"
  type        = string
  default     = "myapp"
}

variable "environment" {
  description = "Project environment (e.g., dev, staging, prod)"
  type        = string
  default     = "dev"
}

# --- IAM Role ---
resource "aws_iam_role" "ec2_role" {
  name = "${var.naming_prefix}-${var.environment}-ec2-role"

  # Trust policy that allows EC2 service to assume this role
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })

  tags = {
    Name        = "${var.naming_prefix}-${var.environment}-ec2-role"
    Environment = var.environment
  }
}

# --- IAM Instance Profile ---
# This is what you actually reference in the `iam_instance_profile` 
# argument of an aws_instance resource.
resource "aws_iam_instance_profile" "ec2_instance_profile" {
  name = "${var.naming_prefix}-${var.environment}-instance-profile"
  role = aws_iam_role.ec2_role.name
}

# --- Example Policy Attachment (Optional) ---
# Attaching a basic policy (e.g., AmazonSSMManagedInstanceCore) so the role has permissions
resource "aws_iam_role_policy_attachment" "ssm_policy" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

# --- Outputs ---
output "instance_profile_name" {
  value       = aws_iam_instance_profile.ec2_instance_profile.name
  description = "The name of the IAM instance profile to be used in EC2 configurations"
}

output "role_arn" {
  value       = aws_iam_role.ec2_role.arn
  description = "The ARN of the created IAM role"
}
```

