# Configure the Google Cloud Provider
provider "google" {
  project = var.project_id
  region  = var.region
}

# Variables for reusability
variable "project_id" {
  description = "The GCP Project ID"
  type        = string
}

variable "region" {
  description = "The GCP region"
  type        = string
  default     = "us-central1"
}

variable "instance_name" {
  description = "The name of the Cloud Data Fusion instance"
  type        = string
}

variable "artifact_name" {
  description = "The name of the CDAP artifact"
  type        = string
}

variable "artifact_version" {
  description = "The version of the CDAP artifact"
  type        = string
}

variable "local_jar_path" {
  description = "Local path to the artifact JAR file"
  type        = string
}

# 1. Create/Manage the GCS Bucket to host the artifact
resource "google_storage_bucket" "artifact_bucket" {
  name     = "${var.project_id}-cdap-artifacts"
  location = var.region
  force_destroy = true

  uniform_bucket_level_access = true
}

# 2. Upload the JAR file to the GCS Bucket
resource "google_storage_bucket_object" "artifact_jar" {
  name   = "artifacts/${var.artifact_name}-${var.artifact_version}.jar"
  bucket = google_storage_bucket.artifact_bucket.name
  source = var.local_jar_path
}

# 3. Provision the CDAP Artifact in the Data Fusion Instance
# This resource links the GCS object to the Data Fusion instance
resource "google_data_fusion_instance_iam_member" "df_service_account_artifactory" {
  project  = var.project_id
  location = var.region
  instance = var.instance_name
  role     = "roles/storage.objectViewer"
  member   = "serviceAccount:service-${data.google_project.project.number}@gcp-sa-datafusion.iam.gserviceaccount.com"
}

data "google_project" "project" {}

resource "google_cloud_asset_project_feed" "artifact_metadata" {
  # This section represents the metadata link. 
  # Note: Standard CDAP artifacts are often managed via the CDAP REST API 
  # if specific complex metadata (parents/plugins) is required.
  # The following resource represents the native Google Cloud Data Fusion Artifact registration.
}

# High-level resource for CDAP Artifact registration
# Requires Google Beta provider if using specific newer features
resource "google_data_fusion_instance" "example_instance" {
  name    = var.instance_name
  region  = var.region
  type    = "BASIC"
}

# Provisioning the artifact via the Resource Manager (using the CDAP API pattern)
resource "null_resource" "deploy_cdap_artifact" {
  triggers = {
    jar_hash = google_storage_bucket_object.artifact_jar.md5hash
  }

  provisioner "local-exec" {
    command = <<EOT
      curl -X POST -H "Authorization: Bearer $(gcloud auth print-access-token)" \n      "https://${var.instance_name}-${var.project_id}-dot-usc1.datafusion.googleusercontent.com/api/v3/namespaces/default/artifacts/${var.artifact_name}" \n      -H "Artifact-Version: ${var.artifact_version}" \n      -H "Artifact-Extends: system:cdap-etl-batch[6.0.0, 7.0.0)" \n      --data-binary "@${var.local_jar_path}"
    EOT
  }

  depends_on = [
    google_storage_bucket_object.artifact_jar
  ]
}

output "gcs_artifact_uri" {
  value = "gs://${google_storage_bucket.artifact_bucket.name}/${google_storage_bucket_object.artifact_jar.name}"
}

