provider "aws" {
  region = "us-west-2"
}

# Data source to fetch existing infrastructure (Default VPC)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "all" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Map of instance configurations
variable "instance_configs" {
  type = map(object({
    instance_type = string
    private_ip    = string
    name          = string
    role          = string
