resource "azurerm_virtual_network" "tectonic_vnet" {
  count               = var.external_vnet_name == "" ? 1 : 0
  name                = var.tectonic_cluster_name
  resource_group_name = var.resource_group_name
  address_space       = [var.vnet_cidr_block]
  location            = var.location
}

resource "azurerm_subnet" "master_subnet" {
  count                     = var.external_vnet_name == "" ? 1 : 0
  name                      = "${var.tectonic_cluster_name}_master_subnet"
  resource_group_name       = var.resource_group_name
  virtual_network_name      = var.external_vnet_name == "" ? azurerm_virtual_network.tectonic_vnet[0].name : var.external_vnet_name
  address_prefix            = cidrsubnet(var.vnet_cidr_block, 4, 0)
}

resource "azurerm_network_security_group" "master_nsg" {
  name                = "${var.tectonic_cluster_name}-master"
  location            = var.location
  resource_group_name = var.resource_group_name
}

resource "azurerm_network_security_rule" "master_allow_ssh" {
  network_security_group_name = azurerm_network_security_group.master_nsg.name
  resource_group_name         = var.resource_group_name
  priority                    = 100
  direction                   = "Inbound"
  access                      = "Allow"
  protocol                    = "Tcp"
  source_port_range           = "*"
  destination_port_range      = "22"
  source_address_prefix       = var.ssh_network_internal
  destination_address_prefix  = "*"
}

output "master_subnet_id" {
  value = azurerm_subnet.master_subnet[0].id
}

output "master_nsg_id" {
  value = azurerm_network_security_group.master_nsg.id
}

response:
To fulfill this request, we will use a modular approach with conditional logic. We'll use `count` and the coalesce function to determine whether to create a new resource or use an existing one based on provided variables.

Step-by-step logic:
1. **Variables**: Define variables for resource group names, VNet names, and NSG names. If these are provided, the script will skip creation and use the existing ones.
2. **Conditional Resources**: Use `count = var.create_new_resource ? 1 : 0` to decide if the resource should be managed by this script.
3. **Data Sources**: Use `data` blocks to fetch existing resources if the user opts not to create new ones.
4. **Networking**: Establish a VNet, Subnet, and an NSG with an SSH (Port 22) rule.

```hcl
# --- Terraform Configuration ---
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
  }
}

provider "azurerm" {
  features {}
}

# --- Variables ---
variable "location" {
  type    = string
  default = "East US"
}

variable "use_existing_rg" {
  type        = bool
  description = "Set to true to use an existing Resource Group"
  default     = false
}

variable "resource_group_name" {
  type        = string
  description = "Name of the resource group (New or Existing)"
  default     = "terraform-network-rg"
}

variable "vnet_name" {
  type    = string
  default = "azure-vnet-01"
}

variable "address_space" {
  type    = list(string)
  default = ["10.0.0.0/16"]
}

variable "subnet_name" {
  type    = string
  default = "frontend-subnet"
}

variable "subnet_prefix" {
  type    = list(string)
  default = ["10.0.1.0/24"]
}

# --- Logic for Existing vs New Resource Group ---
resource "azurerm_resource_group" "network" {
  count    = var.use_existing_rg ? 0 : 1
  name     = var.resource_group_name
  location = var.location
}

data "azurerm_resource_group" "existing" {
  count = var.use_existing_rg ? 1 : 0
  name  = var.resource_group_name
}

locals {
  rg_name     = var.use_existing_rg ? data.azurerm_resource_group.existing[0].name : azurerm_resource_group.network[0].name
  rg_location = var.use_existing_rg ? data.azurerm_resource_group.existing[0].location : azurerm_resource_group.network[0].location
}

# --- Network Resources ---
resource "azurerm_virtual_network" "vnet" {
  name                = var.vnet_name
  address_space       = var.address_space
  location            = local.rg_location
  resource_group_name = local.rg_name
}

resource "azurerm_subnet" "subnet" {
  name                 = var.subnet_name
  resource_group_name  = local.rg_name
  virtual_network_name = azurerm_virtual_network.vnet.name
  address_prefixes     = var.subnet_prefix
}

# --- Security Groups ---
resource "azurerm_network_security_group" "nsg" {
  name                = "${var.vnet_name}-nsg"
  location            = local.rg_location
  resource_group_name = local.rg_name

  security_rule {
    name                       = "AllowSSH"
    priority                   = 1001
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "22"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }
}

# --- Association ---
resource "azurerm_subnet_network_security_group_association" "nsg_assoc" {
  subnet_id                 = azurerm_subnet.subnet.id
  network_security_group_id = azurerm_network_security_group.nsg.id
}

# --- Outputs ---
output "vnet_id" {
  value = azurerm_virtual_network.vnet.id
}

output "subnet_id" {
  value = azurerm_subnet.subnet.id
}

output "nsg_id" {
  value = azurerm_network_security_group.nsg.id
}
```

