  project = "your-project-id" # Replace with your GCP Project ID
  region  = "us-central1"
}

resource "google_compute_health_check" "http2_health_check_us_central1_c" {
  name        = "gc-http2-check-us-central1-c-suffix"
  description = "HTTP/2 health check for services in us-central1-c"

  timeout_sec         = 5
  check_interval_sec  = 5
  healthy_threshold   = 2
  unhealthy_threshold = 2

  http2_health_check {
    port         = 443
    request_path = "/"
    # Setting the proxy_header to NONE is standard, 
    # but can be set to USE_V1 if behind certain proxies.
    proxy_header = "NONE"
  }

  log_config {
    enable = true
  }
}

output "health_check_name" {
  value       = google_compute_health_check.http2_health_check_us_central1_c.name
  description = "The name of the created HTTP/2 health check"
}

output "health_check_self_link" {
  value       = google_compute_health_check.http2_health_check_us_central1_c.self_link
  description = "The URI of the created resource"
}

