# --- Terraform Configuration for Google Anthos on AWS IAM ---

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Variables for customization
variable "anthos_prefix" {
  description = "Prefix for Anthos IAM resources"
  type        = string
  default     = "anthos-gke"
}

variable "gcp_project_number" {
  description = "The numeric GCP Project Number"
  type        = string
}

# 1. API Role: Allows Google GKE Multi-Cloud API to manage AWS resources
resource "aws_iam_role" "api_role" {
  name = "${var.anthos_prefix}-api-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRoleWithWebIdentity"
        Effect = "Allow"
        Principal = {
          Federated = "accounts.google.com"
        }
        Condition = {
          StringEquals = {
            "accounts.google.com:sub" = "service-${var.gcp_project_number}@gcp-sa-gkemulticloud.iam.gserviceaccount.com"
          }
        }
      }
    ]
  })
}

# API Role Policy (GKE Multi-cloud requirements)
resource "aws_iam_role_policy" "api_policy" {
  name = "${var.anthos_prefix}-api-policy"
  role = aws_iam_role.api_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:AttachNetworkInterface",
          "ec2:DetachNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeInstances",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DescribeSubnets",
          "ec2:DescribeVpcs",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeAvailabilityZones",
          "ec2:CreateTags",
          "iam:PassRole"
        ]
        Resource = "*"
        Effect   = "Allow"
      }
    ]
  })
}

# 2. Control Plane Role: Used by the Anthos Control Plane instances
resource "aws_iam_role" "control_plane_role" {
  name = "${var.anthos_prefix}-control-plane-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

# Attach common policies for Control Plane (Network/ELB management)
resource "aws_iam_role_policy_attachment" "cp_autoscaling" {
  role       = aws_iam_role.control_plane_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2FullAccess"
}

# Control Plane Instance Profile
resource "aws_iam_instance_profile" "control_plane_profile" {
  name = "${var.anthos_prefix}-control-plane-profile"
  role = aws_iam_role.control_plane_role.name
}

# 3. Node Pool Role: Used by worker nodes to pull images and log
resource "aws_iam_role" "node_pool_role" {
  name = "${var.anthos_prefix}-node-pool-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

# Standard AWS Managed Policies for Worker Nodes
resource "aws_iam_role_policy_attachment" "node_ecr" {
  role       = aws_iam_role.node_pool_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
}

resource "aws_iam_role_policy_attachment" "node_worker" {
  role       = aws_iam_role.node_pool_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
}

resource "aws_iam_role_policy_attachment" "node_ssm" {
  role       = aws_iam_role.node_pool_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

# Node Pool Instance Profile
resource "aws_iam_instance_profile" "node_pool_profile" {
  name = "${var.anthos_prefix}-node-pool-profile"
  role = aws_iam_role.node_pool_role.name
}

# Outputs for use in GKE Multi-cloud registration
output "api_role_arn" {
  value = aws_iam_role.api_role.arn
}

output "control_plane_profile_arn" {
  value = aws_iam_instance_profile.control_plane_profile.arn
}

output "node_pool_profile_arn" {
  value = aws_iam_instance_profile.node_pool_profile.arn
}

