extracted_code:
# Terraform configuration for an etcd cluster on Azure (Flatcar Container Linux)

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
  }
}

provider "azurerm" {
  features {}
}

variable "prefix" {
  default = "etcd-coreos"
}

variable "location" {
  default = "East US"
}

variable "vm_size" {
  default = "Standard_B2s"
}

variable "node_count" {
  default = 3
}

variable "ssh_public_key" {
  description = "Public SSH key for VM authentication"
  type        = string
}

resource "azurerm_resource_group" "main" {
  name     = "${var.prefix}-rg"
  location = var.location
  tags = {
    Environment = "Production"
    Component   = "etcd"
  }
}

resource "azurerm_virtual_network" "main" {
  name                = "${var.prefix}-vnet"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
}

resource "azurerm_subnet" "internal" {
  name                 = "etcd-subnet"
  resource_group_name  = azurerm_resource_group.main.name
  virtual_network_name = azurerm_virtual_network.main.name
  address_prefixes     = ["10.0.1.0/24"]
}

resource "azurerm_network_security_group" "etcd_nsg" {
  name                = "${var.prefix}-nsg"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  security_rule {
    name                       = "allow_ssh"
    priority                   = 100
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "22"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }

  security_rule {
    name                       = "etcd_client"
    priority                   = 110
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "2379"
    source_address_prefix      = "10.0.0.0/16"
    destination_address_prefix = "*"
  }

  security_rule {
    name                       = "etcd_peer"
    priority                   = 120
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "2380"
    source_address_prefix      = "10.0.0.0/16"
    destination_address_prefix = "*"
  }
}

resource "azurerm_network_interface" "etcd_nic" {
  count               = var.node_count
  name                = "${var.prefix}-nic-${count.index}"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = azurerm_subnet.internal.id
    private_ip_address_allocation = "Dynamic"
  }
}

resource "azurerm_network_interface_security_group_association" "nsg_assoc" {
  count                     = var.node_count
  network_interface_id      = azurerm_network_interface.etcd_nic[count.index].id
  network_security_group_id = azurerm_network_security_group.etcd_nsg.id
}

resource "azurerm_linux_virtual_machine" "etcd_node" {
  count               = var.node_count
  name                = "${var.prefix}-node-${count.index}"
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  size                = var.vm_size
  admin_username      = "core"

  network_interface_ids = [
    azurerm_network_interface.etcd_nic[count.index].id,
  ]

  admin_ssh_key {
    username   = "core"
    public_key = var.ssh_public_key
  }

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Premium_LRS" # Premium SSD for etcd latency requirements
    disk_size_gb         = 32
  }

  # Using Flatcar Container Linux (the successor to CoreOS)
  source_image_reference {
    publisher = "kinvolk"
    offer     = "flatcar-container-linux"
    sku       = "stable"
    version   = "latest"
  }

  # Ignition / Custom Data to bootstrap etcd
  # In a production scenario, you would pass your etcd.yaml or Ignition config here
  custom_data = base64encode(<<-EOF
    #cloud-config
    write_files:
      - path: /etc/etcd/etcd.conf
        permissions: '0644'
        content: |
          ETCD_NAME="etcd-${count.index}"
          ETCD_INITIAL_CLUSTER_TOKEN="etcd-cluster-1"
          ETCD_INITIAL_CLUSTER_STATE="new"
    # Note: Full TLS cert generation and dynamic IP discovery should be handled via a discovery service or Ignition.
    EOF
  )

  tags = {
    Cluster = "etcd"
    Role    = "member"
  }
}

output "etcd_private_ips" {
  value = azurerm_network_interface.etcd_nic[*].private_ip_address
}

