To provision a Google Cloud project with BigQuery resources using service account impersonation, we must configure the Google provider twice: once to authenticate as the initial identity (caller) to fetch an OAuth2 token for the target service account, and a second time to execute the actual resource creation.

The configuration below includes the provider setup for impersonation, the project creation, enabling the BigQuery API, and creating the dataset and table.

```hcl
# 1. Provider configuration for impersonation
provider "google" {
  alias = "impersonation"
}

data "google_service_account_access_token" "default" {
  provider               = google.impersonation
  target_service_account = "terraform-deployer@your-admin-project.iam.gserviceaccount.com"
  scopes                 = ["userinfo-email", "cloud-platform"]
  lifetime               = "1200s"
}

# 2. Main Google Provider using the impersonated token
provider "google" {
  project      = "my-new-bq-project-id"
  region       = "us-central1"
  access_token = data.google_service_account_access_token.default.access_token
}

# 3. Project Creation (Requires Billing Account and Organization ID)
resource "google_project" "main_project" {
  name            = "BigQuery Project"
  project_id      = "my-new-bq-project-id"
  billing_account = "012345-6789AB-CDEF01" # Replace with your billing ID
  org_id          = "1234567890"          # Replace with your Org ID or folder_id
}

# 4. Enable BigQuery API
resource "google_project_service" "bigquery_api" {
  project                    = google_project.main_project.project_id
  service                    = "bigquery.googleapis.com"
  disable_dependent_services = true
}

# 5. BigQuery Dataset
resource "google_bigquery_dataset" "analytics_dataset" {
  depends_on = [google_project_service.bigquery_api]
  project    = google_project.main_project.project_id
  dataset_id = "app_analytics"
  location   = "US"

  labels = {
    environment = "production"
  }
}

# 6. BigQuery Table
resource "google_bigquery_table" "events_table" {
  project    = google_project.main_project.project_id
  dataset_id = google_bigquery_dataset.analytics_dataset.dataset_id
  table_id   = "user_events"

  deletion_protection = false

  schema = <<EOF
[
  {
    "name": "event_timestamp",
    "type": "TIMESTAMP",
    "mode": "REQUIRED"
  },
  {
    "name": "event_name",
    "type": "STRING",
    "mode": "REQUIRED"
  },
  {
    "name": "user_id",
    "type": "STRING",
    "mode": "NULLABLE"
  }
]
EOF
}

# 7. Outputs
output "project_id" {
  value       = google_project.main_project.project_id
  description = "The ID of the created GCP project."
}

output "dataset_id" {
  value       = google_bigquery_dataset.analytics_dataset.dataset_id
  description = "The ID of the BigQuery dataset."
}

output "table_id" {
  value       = google_bigquery_table.events_table.table_id
