# Define provider and variables
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

variable "project_name" {
  type    = string
  default = "tf-managed-project"
}

variable "billing_account" {
  type    = string
  description = "The alphanumeric ID of the billing account"
}

variable "org_id" {
  type    = string
  description = "The numeric ID of the organization"
}

variable "services_to_enable" {
  type    = list(string)
  default = [
    "compute.googleapis.com",
    "iam.googleapis.com",
    "cloudresourcemanager.googleapis.com"
  ]
}

# 1. Create the Google Cloud Project
resource "random_id" "project_suffix" {
  byte_length = 4
}

resource "google_project" "new_project" {
  name            = var.project_name
  project_id      = "${var.project_name}-${random_id.project_suffix.hex}"
  billing_account = var.billing_account
  org_id          = var.org_id
}

# 2. Enable APIs
resource "google_project_service" "project_apis" {
  for_each = toset(var.services_to_enable)
  project  = google_project.new_project.project_id
  service  = each.key

  disable_on_destroy = false
}

# 3. Create a Service Account
resource "google_service_account" "project_sa" {
  account_id   = "tf-deployer-sa"
  display_name = "Terraform Managed Service Account"
  project      = google_project.new_project.project_id
  depends_on   = [google_project_service.project_apis]
}

# 4. Assign IAM Roles to the Service Account
resource "google_project_iam_member" "sa_editor_role" {
  project = google_project.new_project.project_id
  role    = "roles/editor"
  member  = "serviceAccount:${google_service_account.project_sa.email}"
}

# 5. Create Service Account Key
resource "google_service_account_key" "sa_key" {
  service_account_id = google_service_account.project_sa.name
  public_key_type    = "TYPE_X509_PEM_FILE"
}

# 6. Outputs
output "project_id" {
  value       = google_project.new_project.project_id
  description = "The unique ID of the newly created project"
}

output "service_account_email" {
  value       = google_service_account.project_sa.email
  description = "The email of the created service account"
}

output "service_account_private_key" {
  value       = google_service_account_key.sa_key.private_key
  description = "The private key for the service account (base64 encoded)"
  sensitive   = true
}

response:
To provision a Google Cloud project along with its associated APIs, service accounts, and IAM roles, we use the `google_project` resource and the `google_project_service` resource to manage dependencies correctly. 

Key steps included in the configuration:
1. **Project Creation**: Defines the project name and links it to an organization or billing account.
2. **API Activation**: Uses a loop to enable common APIs (Compute, IAM, Resource Manager).
3. **Service Account**: Creates a dedicated service account within the new project.
4. **IAM Binding**: Assigns the "Editor" role to the new service account.
5. **Key Management**: Generates a JSON private key for the service account.
6. **Outputs**: Returns the Project ID and the sensitive Service Account Key.

```hcl
# Define provider and variables
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

variable "project_name" {
  type    = string
  default = "tf-managed-project"
}

variable "billing_account" {
  type    = string
  description = "The alphanumeric ID of the billing account"
}

variable "org_id" {
  type    = string
  description = "The numeric ID of the organization"
}

variable "services_to_enable" {
  type    = list(string)
  default = [
    "compute.googleapis.com",
    "iam.googleapis.com",
    "cloudresourcemanager.googleapis.com"
  ]
}

# 1. Create the Google Cloud Project
resource "random_id" "project_suffix" {
  byte_length = 4
}

resource "google_project" "new_project" {
  name            = var.project_name
  project_id      = "${var.project_name}-${random_id.project_suffix.hex}"
  billing_account = var.billing_account
  org_id          = var.org_id
}

# 2. Enable APIs
resource "google_project_service" "project_apis" {
  for_each = toset(var.services_to_enable)
  project  = google_project.new_project.project_id
  service  = each.key

  disable_on_destroy = false
}

# 3. Create a Service Account
resource "google_service_account" "project_sa" {
  account_id   = "tf-deployer-sa"
  display_name = "Terraform Managed Service Account"
  project      = google_project.new_project.project_id
  depends_on   = [google_project_service.project_apis]
}

# 4. Assign IAM Roles to the Service Account
resource "google_project_iam_member" "sa_editor_role" {
  project = google_project.new_project.project_id
  role    = "roles/editor"
  member  = "serviceAccount:${google_service_account.project_sa.email}"
}

# 5. Create Service Account Key
resource "google_service_account_key" "sa_key" {
  service_account_id = google_service_account.project_sa.name
  public_key_type    = "TYPE_X509_PEM_FILE"
}

# 6. Outputs
output "project_id" {
  value       = google_project.new_project.project_id
  description = "The unique ID of the newly created project"
}

output "service_account_email" {
  value       = google_service_account.project_sa.email
  description = "The email of the created service account"
}

output "service_account_private_key" {
  value       = google_service_account_key.sa_key.private_key
  description = "The private key for the service account (base64 encoded)"
  sensitive   = true
}
```

