To provision this infrastructure on Google Cloud Platform using modules from a GitHub repository, we will define the provider, the VPC networking, the Serverless VPC Access connector for serverless-to-VPC communication, firewall rules for VM access, and the Compute Engine instance.

Here is the complete Terraform configuration:

```hcl
# Configure the Google Cloud Provider
provider "google" {
  project = "your-project-id"
  region  = "us-central1"
}

# 1. VPC Network Module
module "vpc" {
  source  = "terraform-google-modules/network/google"
  version = "~> 9.1"

  project_id   = "your-project-id"
  network_name = "main-vpc"
  routing_mode = "GLOBAL"

  subnets = [
    {
      subnet_name   = "subnet-01"
      subnet_ip     = "10.10.10.0/24"
      subnet_region = "us-central1"
    },
    {
      subnet_name   = "subnet-serverless"
      subnet_ip     = "10.10.11.0/28" # Must be a /28 for VPC Access
      subnet_region = "us-central1"
    }
  ]
}

# 2. Serverless VPC Access Connector
# This allows Cloud Run/Functions to access the VPC
resource "google_vpc_access_connector" "connector" {
  name          = "serverless-connector"
  region        = "us-central1"
  ip_cidr_range = "10.8.0.0/28"
  network       = module.vpc.network_name
}

# 3. Firewall Rules
# Allow SSH access and internal communication
resource "google_compute_firewall" "allow_ssh" {
  name    = "allow-ssh"
  network = module.vpc.network_name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["ssh-enabled"]
}

# 4. Compute Engine VM Module
# Using a module from the official Google GitHub repository
module "compute_instance" {
  source  = "terraform-google-modules/vm/google//modules/compute_instance"
  version = "~> 11.0"

  project_id         = "your-project-id"
  region             = "us-central1"
  zone               = "us-central1-a"
  name               = "web-server"
  machine_type       = "e2-medium"
  subnetwork         = module.vpc.subnets_names[0]
  subnetwork_project = "your-project-id"

  num_instances = 1
  tags          = ["ssh-enabled"]

  source_image         = "debian-cloud/debian-11"
  source_image_project = "debian-cloud"

  network_interface {
    network    = module.vpc.network_name
    subnetwork = module.vpc.subnets_names[0]
    access_config {
      # Include this block to give the VM a public IP
    }
  }
}

# Outputs
output "vpc_name" {
  value = module.vpc.network_name
}

output "vm_external_ip" {
  value = module.compute_instance.instances_details[0].network_interface[0].access_config[0].nat_ip
}

output "serverless_connector_id" {
  value = google_vpc_access_connector.connector.id
}
