# --- Terraform Backend Configuration ---
# This stores the state file in a GCS bucket for collaboration and persistence.
terraform {
  required_version = ">= 1.0.0"
  backend "gcs" {
    bucket  = "your-terraform-state-bucket" # Replace with your existing bucket name
    prefix  = "terraform/state/multi-project"
  }
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 4.0"
    }
  }
}

# --- Provider Configuration ---
# Uses the service account key provided via the environment variable GOOGLE_APPLICATION_CREDENTIALS
# or explicitly pointed to here.
provider "google" {
  region      = "us-central1"
}

# --- Variables ---
locals {
  org_id          = "123456789012"             # Replace with your Organization ID
  folder_id       = "987654321098"             # Replace with your Folder ID
  billing_account = "012345-ABCDEF-GHIJKL"     # Replace with your Billing Account ID
  shared_prefix   = "shared-infra"
  demo_prefix     = "demo-app"
}

# --- 1. Shared Infrastructure Project ---
resource "google_project" "shared_project" {
  name            = "Shared Infrastructure"
  project_id      = "${local.shared_prefix}-${random_id.suffix.hex}"
  folder_id       = local.folder_id
  billing_account = local.billing_account
  labels = {
    environment = "common"
  }
}

# --- 2. Demo Application Project ---
resource "google_project" "demo_project" {
  name            = "Demo Application"
  project_id      = "${local.demo_prefix}-${random_id.suffix.hex}"
  folder_id       = local.folder_id
  billing_account = local.billing_account
  labels = {
    environment = "demo"
  }
}

# Random suffix to ensure global project ID uniqueness
resource "random_id" "suffix" {
  byte_length = 4
}

# --- 3. Enable Required APIs for Projects ---

# APIs for the Shared Project (e.g., Compute and Container Registry)
resource "google_project_service" "shared_apis" {
  for_each = toset([
    "compute.googleapis.com",
    "container.googleapis.com",
    "cloudresourcemanager.googleapis.com"
  ])
  project            = google_project.shared_project.project_id
  service            = each.key
  disable_on_destroy = false
}

# APIs for the Demo Project (e.g., App Engine and Cloud Run)
resource "google_project_service" "demo_apis" {
  for_each = toset([
    "compute.googleapis.com",
    "run.googleapis.com",
    "iam.googleapis.com",
    "cloudresourcemanager.googleapis.com"
  ])
  project            = google_project.demo_project.project_id
  service            = each.key
  disable_on_destroy = false
}

# --- Outputs ---
output "shared_project_id" {
  value       = google_project.shared_project.project_id
  description = "The ID of the Shared Infrastructure project"
}

output "demo_project_id" {
  value       = google_project.demo_project.project_id
  description = "The ID of the Demo Application project"
}

