# Terraform configuration for an AWS EC2 instance in us-west-2

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# 1. Configure the AWS Provider
provider "aws" {
  region = "us-west-2"
}

# 2. Define a variable for the instance name to allow customization
variable "instance_name" {
  description = "The name of the EC2 instance"
  type        = string
  default     = "terraform-linux-instance"
}

# 3. Define a variable for the instance type with a sensible default
variable "instance_type" {
  description = "EC2 instance size"
  type        = string
  default     = "t3.micro"
}

# 4. Use a Data Source to find the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# 5. Provision the EC2 Instance
resource "aws_instance" "app_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = var.instance_type

  tags = {
    Name = var.instance_name
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# 6. Output the Instance ID and Public IP
output "instance_id" {
  description = "ID of the EC2 instance"
  value       = aws_instance.app_server.id
}

output "instance_public_ip" {
  description = "Public IP address of the EC2 instance"
  value       = aws_instance.app_server.public_ip
}

