# ---- Provider Configuration ----
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# ---- Variables ----
variable "aws_region" {
  default = "us-east-1"
}

variable "vpc_cidr" {
  default = "10.0.0.0/16"
}

variable "cluster_name" {
  default = "terraform-cluster"
}

variable "additional_tags" {
  type    = map(string)
  default = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# ---- Data Sources ----
data "aws_availability_zones" "available" {
  state = "available"
}

# ---- Network Resources ----

# 1. VPC with Custom DNS Support
resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = merge(
    var.additional_tags,
    {
      Name = "${var.cluster_name}-vpc"
    }
  )
}

# 2. Public Subnets (For Load Balancers and Public Endpoints)
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(var.vpc_cidr, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = merge(
    var.additional_tags,
    {
      Name                                        = "${var.cluster_name}-public-${count.index}"
      "kubernetes.io/role/elb"                    = "1" # Tag for K8s ELB discovery
    }
  )
}

# 3. Private Subnets (For Cluster Nodes and Private Master Endpoints)
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(var.vpc_cidr, 8, count.index + 10)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = merge(
    var.additional_tags,
    {
      Name                                        = "${var.cluster_name}-private-${count.index}"
      "kubernetes.io/role/internal-elb"           = "1" # Tag for K8s Internal ELB discovery
    }
  )
}

# 4. Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = merge(var.additional_tags, { Name = "${var.cluster_name}-igw" })
}

# 5. NAT Gateway (Enable private subnets to reach the internet)
resource "aws_eip" "nat" {
  domain = "vpc"
  tags   = var.additional_tags
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public[0].id

  tags = merge(var.additional_tags, { Name = "${var.cluster_name}-nat" })
}

# 6. Route Tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = merge(var.additional_tags, { Name = "${var.cluster_name}-rt-public" })
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = merge(var.additional_tags, { Name = "${var.cluster_name}-rt-private" })
}

# Route Table Associations
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# 7. Security Groups
resource "aws_security_group" "cluster_sg" {
  name        = "${var.cluster_name}-sg"
  description = "Security group for cluster control plane and nodes"
  vpc_id      = aws_vpc.main.id

  # Allow internal communication between cluster resources
  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  # Allow HTTPS for Public/Private Master Endpoints access
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Narrow this down for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(var.additional_tags, { Name = "${var.cluster_name}-sg" })
}

# ---- Outputs ----
output "vpc_id" {
  value = aws_vpc.main.id
}

output "private_subnets" {
  value = aws_subnet.private[*].id
}

output "public_subnets" {
  value = aws_subnet.public[*].id
}

output "cluster_security_group_id" {
  value = aws_security_group.cluster_sg.id
}

