response:
To fulfill this request, we will use the `google_compute_instance_group` resource. The configuration is designed to be flexible, using a map of objects to define the group name, the zone, the list of instance self-links, and the optional named ports.

Step-by-step logic:
1. **Variable Definition**: We define a map of objects containing the group details.
2. **Resource Iteration**: We use `for_each` to iterate through the map, allowing for the creation of multiple groups in different zones.
3. **Dynamic Blocks**: We use a `dynamic "named_port"` block to process the optional list of ports for each group.
4. **Member Assignment**: The `instances` attribute accepts the list of existing self-links provided in the input.

```hcl
variable "project_id" {
  description = "The ID of the project where resources will be created"
  type        = string
}

variable "instance_groups_config" {
  description = "A map defining the instance groups to be created"
  type = map(object({
    zone      = string
    instances = list(string)
    named_ports = optional(list(object({
      name = string
      port = number
    })), [])
  }))
  default = {
    "web-group-a" = {
      zone      = "us-central1-a"
      instances = ["https://www.googleapis.com/compute/v1/projects/my-project/zones/us-central1-a/instances/instance-1"]
      named_ports = [
        { name = "http", port = 80 },
        { name = "https", port = 443 }
      ]
    }
  }
}

provider "google" {
  project = var.project_id
}

resource "google_compute_instance_group" "unmanaged_groups" {
  for_each = var.instance_groups_config

  name        = each.key
  description = "Terraform managed unmanaged instance group for ${each.key}"
  zone        = each.value.zone
  instances   = each.value.instances

  # Handle optional named ports using a dynamic block
  dynamic "named_port" {
    for_each = each.value.named_ports
    content {
      name = named_port.value.name
      port = named_port.value.port
    }
  }
}

output "instance_group_self_links" {
  value = { for k, v in google_compute_instance_group.unmanaged_groups : k => v.self_link }
  description = "The self-links of the created instance groups"
}
```

