# --- Provider and Variables ---
provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  default = "us-east-1"
}

variable "environment" {
  default = "production"
}

# --- Lambda Function Resource ---

# IAM Role for Lambda execution
resource "aws_iam_role" "lambda_exec_role" {
  name = "lambda_exec_role_${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Attach Basic Execution Policy (Logs) to the Lambda Role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Dummy source code for the Lambda
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"
  source {
    content  = "def handler(event, context): return {'statusCode': 200, 'body': 'Hello'}"
    filename = "index.py"
  }
}

# The Lambda Function
resource "aws_lambda_function" "target_function" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "app_function_${var.environment}"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  tags = {
    Environment = var.environment
  }
}

# --- IAM User: Jenkins (Deployment User) ---

resource "aws_iam_user" "jenkins" {
  name = "jenkins-deployer-${var.environment}"
  path = "/serviceaccounts/"
}

resource "aws_iam_access_key" "jenkins_key" {
  user = aws_iam_user.jenkins.name
}

# Policy allowing Jenkins to update the Lambda code and configuration
resource "aws_iam_user_policy" "jenkins_policy" {
  name = "JenkinsLambdaDeploymentPolicy"
  user = aws_iam_user.jenkins.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "lambda:UpdateFunctionCode",
          "lambda:UpdateFunctionConfiguration",
          "lambda:GetFunction",
          "lambda:ListVersionsByFunction"
        ]
        Effect   = "Allow"
        Resource = aws_lambda_function.target_function.arn
      }
    ]
  })
}

# --- IAM User: Lambda Invoker (Application User) ---

resource "aws_iam_user" "invoker" {
  name = "lambda-invoker-${var.environment}"
  path = "/serviceaccounts/"
}

resource "aws_iam_access_key" "invoker_key" {
  user = aws_iam_user.invoker.name
}

# Policy allowing the user only to invoke this specific Lambda
resource "aws_iam_user_policy" "invoker_policy" {
  name = "LambdaInvokePolicy"
  user = aws_iam_user.invoker.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "lambda:InvokeFunction"
        Effect   = "Allow"
        Resource = aws_lambda_function.target_function.arn
      }
    ]
  })
}

# --- Outputs ---

output "lambda_arn" {
  value = aws_lambda_function.target_function.arn
}

output "jenkins_access_key_id" {
  value = aws_iam_access_key.jenkins_key.id
}

