```hcl
# Terraform configuration to provision an AWS web server with networking and security

# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. VPC and Networking
resource "aws_vpc" "web_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "web-server-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.web_vpc.id
  tags = {
    Name = "web-server-igw"
  }
}

resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.web_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Designated Availability Zone
  tags = {
    Name = "web-server-subnet"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.web_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "web-server-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# 3. Security Group (SSH, HTTP, HTTPS)
resource "aws_security_group" "web_sg" {
  name        = "allow_web_traffic"
  description = "Allow SSH, HTTP and HTTPS inbound traffic"
  vpc_id      = aws_vpc.web_vpc.id

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTP"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-server-sg"
  }
}

# 4. Key Pair
# Note: You should replace the public_key with your own local SSH public key string
resource "aws_key_pair" "deployer" {
  key_name   = "web-server-key"
  public_key = "ssh-rsa AAAAB3Nza...example_key...user@host"
}

# 5. EC2 Instance
resource "aws_instance" "web_server" {
  ami               = "ami-0c7217cdde317cfec" # Designated AMI (Ubuntu 22.04 LTS us-east-1 example)
  instance_type     = "t2.micro"
  subnet_id         = aws_subnet.public_subnet.id
  availability_zone = "us-east-1a"
  key_name          = aws_key_pair.deployer.key_name

  vpc_security_group_ids = [aws_security_group.web_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              sudo apt-get update
              sudo apt-get install -y apache2
              sudo systemctl start apache2
              sudo systemctl enable apache2
              EOF

  tags = {
    Name = "Terraform-Web-Server"
  }
}

# 6. Elastic IP
resource "aws_eip" "web_eip" {
  instance = aws_instance.web_server.id
  domain   = "vpc"

  depends_on = [aws_internet_gateway.igw]

  tags = {
    Name = "web-server-eip"
  }
}

# Outputs
output "public_ip" {
  value       = aws_eip.web_eip.public_ip
  description = "The Elastic IP address of the web server"
}
