# 1. Provide the AWS Provider configuration with explicit credentials
# Note: In production, it is recommended to use environment variables or IAM roles.
provider "aws" {
  region     = var.aws_region
  access_key = var.aws_access_key
  secret_key = var.aws_secret_key
}

# 2. Define Input Variables
variable "aws_region" {
  type    = string
  default = "us-east-1"
}

variable "aws_access_key" {
  type      = string
  sensitive = true
}

variable "aws_secret_key" {
  type      = string
  sensitive = true
}

variable "app_name" {
  type    = string
  default = "TerraformAI-Demo-App"
}

variable "api_token" {
  type      = string
  sensitive = true
  default   = "extremely-confidential-token-12345"
}

# 3. Create a local configuration file
# This file combines regular data (app_name) and sensitive data (api_token)
resource "local_file" "app_config" {
  filename = "${path.module}/app_config.json"
  content  = jsonencode({
    application_name = var.app_name
    deployment_region = var.aws_region
    api_access_token  = var.api_token
    generated_at      = timestamp()
  })
}

# 4. Define Outputs
# Regular output
output "application_name" {
  description = "The name of the application"
  value       = var.app_name
}

# Protected/Sensitive output
# Marking 'sensitive = true' prevents the value from being printed to the console during plan/apply
output "confidential_api_token" {
  description = "The API token (redacted in CLI)"
  value       = var.api_token
  sensitive   = true
}

output "config_file_path" {
  description = "Path to the generated local config file"
  value       = local_file.app_config.filename
}

