# Terraform configuration to manage Google Cloud Identity Groups and Members

terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  # Credentials and Project should be configured via environment variables or CLI
}

# Variable definitions for flexibility
variable "customer_id" {
  description = "The customer ID for the Cloud Identity account (e.g., C01abcde)"
  type        = string
}

variable "group_id" {
  description = "The primary email address for the group (e.g., team-name@example.com)"
  type        = string
}

variable "display_name" {
  description = "The display name of the group"
  type        = string
  default     = "Engineering Team"
}

variable "description" {
  description = "A description for the group"
  type        = string
  default     = "Infrastructure managed by Terraform"
}

variable "managers" {
  description = "List of user emails to be added as group managers"
  type        = list(string)
  default     = ["admin@example.com"]
}

variable "members" {
  description = "List of user emails to be added as regular group members"
  type        = list(string)
  default     = ["user1@example.com", "user2@example.com"]
}

# 1. Create the Cloud Identity Group
resource "google_cloud_identity_group" "cloud_group" {
  display_name = var.display_name
  description  = var.description

  parent = "customers/${var.customer_id}"

  group_key {
    id = var.group_id
  }

  # Labels define the type of group. "cloudidentity.googleapis.com/groups.discussion_forum" is standard.
  labels = {
    "cloudidentity.googleapis.com/groups.discussion_forum" = ""
  }
}

# 2. Assign Managers to the Group
resource "google_cloud_identity_group_membership" "managers" {
  for_each = toset(var.managers)
  group    = google_cloud_identity_group.cloud_group.id

  preferred_member_key {
    id = each.value
  }

  roles {
    name = "MEMBER"
  }
  roles {
    name = "MANAGER"
  }
}

# 3. Assign Regular Members to the Group
resource "google_cloud_identity_group_membership" "members" {
  for_each = toset(var.members)
  group    = google_cloud_identity_group.cloud_group.id

  preferred_member_key {
    id = each.value
  }

  roles {
    name = "MEMBER"
  }
}

# Output the Group ID for reference
output "group_name" {
  value       = google_cloud_identity_group.cloud_group.name
  description = "The resource name of the generated Group"
}

