variable "vpc_id" {
  description = "The ID of the VPC where security groups will be created"
  type        = string
}

variable "app_name" {
  description = "The name of the application"
  type        = string
  default     = "web-app"
}

variable "environment" {
  description = "Deployment environment (e.g., dev, staging, prod)"
  type        = string
  default     = "dev"
}

# Example Security Group for an Application Load Balancer or Web Server
resource "aws_security_group" "app_sg" {
  name        = "${var_app_name}-${var.environment}-sg"
  description = "Security group to control inbound and outbound traffic for ${var.app_name}"
  vpc_id      = var.vpc_id

  # Inbound Rule: Allow HTTP traffic from anywhere
  ingress {
    description      = "Allow HTTP from anywhere"
    from_port        = 80
    to_port          = 80
    protocol         = "tcp"
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  # Inbound Rule: Allow HTTPS traffic from anywhere
  ingress {
    description      = "Allow HTTPS from anywhere"
    from_port        = 443
    to_port          = 443
    protocol         = "tcp"
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  # Inbound Rule: Allow SSH (example restricted to a specific CIDR)
  ingress {
    description      = "SSH access"
    from_port        = 22
    to_port          = 22
    protocol         = "tcp"
    cidr_blocks      = ["10.0.0.0/16"] # Restricted to internal VPC range
  }

  # Outbound Rule: Allow all traffic to the internet
  egress {
    description      = "Allow all outbound traffic"
    from_port        = 0
    to_port          = 0
    protocol         = "-1" # -1 means all protocols
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  tags = {
    Name        = "${var.app_name}-${var.environment}-sg"
    Environment = var.environment
    Application = var.app_name
    ManagedBy   = "Terraform"
  }
}

output "security_group_id" {
  value       = aws_security_group.app_sg.id
  description = "The ID of the created security group"
}

reference:
variable "name" {
  description = "Name of application"
}

variable "env" {
  description = "Environment tag, e.g., prod"
}

variable "vpc_cidr" {
  description = "CIDR block of the VPC"
}

variable "vpc_id" {
  description = "ID of the VPC"
}

output "internal_id" {
  description = "ID of internal ALB security group"
  value       = aws_security_group.internal_alb.id
}

output "external_id" {
  description = "ID of external ALB security group"
  value       = aws_security_group.external_alb.id
}

resource "aws_security_group" "internal_alb" {
  name        = "${var.name}-internal-alb"
  vpc_id      = var.vpc_id
  description = "Allows internal VPC traffic through the ALB"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }

  tags {
    Name        = "${var.name}-internal-alb"
    Environment = var.env
  }
}

resource "aws_security_group" "external_alb" {
  name        = "${var.name}-external-alb"
  vpc_id      = var.vpc_id
  description = "Allows all external traffic through the ALB"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }

  tags {
    Name        = "${var.name}-external-alb"
    Environment = var.env
  }
}

extracted_code:
# Terraform Configuration for Concourse CI on AWS

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- VPC & Networking ---

resource "aws_vpc" "concourse_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "concourse-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.concourse_vpc.id
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.concourse_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags                    = { Name = "concourse-public-${count.index}" }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.concourse_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# --- Security Groups ---

resource "aws_security_group" "alb_sg" {
  name        = "concourse-alb-sg"
  description = "Allow HTTP/S to LB"
  vpc_id      = aws_vpc.concourse_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "concourse_nodes" {
  name        = "concourse-node-sg"
  vpc_id      = aws_vpc.concourse_vpc.id

  # Web UI and API from ALB
  ingress {
    from_port       = 8080
    to_port         = 8080
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  # TSA Tunnel (used by workers)
  ingress {
    from_port   = 2222
    to_port     = 2222
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Storage & S3 ---

resource "aws_s3_bucket" "concourse_assets" {
  bucket        = "concourse-ci-assets-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# --- Load Balancer ---

resource "aws_lb" "concourse_alb" {
  name               = "concourse-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "concourse_web" {
  name     = "concourse-web-tg"
  port     = 8080
  protocol = "HTTP"
  vpc_id   = aws_vpc.concourse_vpc.id

  health_check {
    path = "/api/v1/info"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.concourse_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.concourse_web.arn
  }
}

# --- Route 53 ---

data "aws_route53_zone" "selected" {
  name         = "example.com." # Replace with your domain
  private_zone = false
}

resource "aws_route53_record" "concourse" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "concourse.${data.aws_route53_zone.selected.name}"
  type    = "A"

  alias {
    name                   = aws_lb.concourse_alb.dns_name
    zone_id                = aws_lb.concourse_alb.zone_id
    evaluate_target_health = true
  }
}

# --- Compute (Example EC2 Instance for Web Node) ---

resource "aws_instance" "concourse_web" {
  ami           = "ami-0c7217cdde317cfec" # Amazon Linux 2 (Example ID)
  instance_type = "t3.medium"
  subnet_id     = aws_subnet.public[0].id
  vpc_security_group_ids = [aws_security_group.concourse_nodes.id]

  tags = {
    Name = "concourse-web"
  }

  # IAM profile for S3 access would be defined here
}

resource "aws_lb_target_group_attachment" "concourse_web_attach" {
  target_group_arn = aws_lb_target_group.concourse_web.arn
  target_id        = aws_instance.concourse_web.id
  port             = 8080
}

# --- Outputs ---

output "concourse_url" {
  value = "http://${aws_route53_record.concourse.fqdn}"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.concourse_assets.id
}

reference:
variable "aws_region" {
    type = "string"
    default =  "eu-west-1"
}
variable "boshers" {
  type = "list"
}
variable "ci_hostname" {
type = "string"
}
variable "ci_dns_zone_id" {
type = "string"
}
variable "ssl_cert_arn" {
type = "string"
}
variable "aws_access_key" {
  type = "string"
}
variable "aws_secret_key" {
  type = "string"
}


# Create a Concourse security group
resource "aws_security_group" "concourse-sg" {
  name        = "concourse-sg"
  description = "Concourse security group"
  vpc_id      = "${aws_vpc.default.id}"
  tags {
  Name = "concourse-sg"
  component = "concourse"
  }

  # outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # inbound connections from ELB
  ingress {
    from_port   = 8080
    to_port     = 8080
    protocol    = "tcp"
    security_groups = ["${aws_security_group.elb-sg.id}"]
  }

  ingress {
    from_port   = 2222
    to_port     = 2222
    protocol    = "tcp"
    security_groups = ["${aws_security_group.elb-sg.id}"]
  }
}

# Create an ELB security group
resource "aws_security_group" "elb-sg" {
  name        = "elb-sg"
  description = "ELB security group"
  vpc_id      = "${aws_vpc.default.id}"
  tags {
  Name = "elb-sg"
  component = "concourse"
  }

  # outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # inbound https
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # inbound https
  ingress {
    from_port   = 2222
    to_port     = 2222
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

}

# Create a new load balancer
resource "aws_elb" "concourse" {
  name = "concourse-elb"
  subnets = ["${aws_subnet.ops_services.id}"]
  security_groups = ["${aws_security_group.elb-sg.id}"]

  listener {
    instance_port = 8080
    instance_protocol = "http"
    lb_port = 80
    lb_protocol = "http"
  }

  listener {
    instance_port = 8080
    instance_protocol = "tcp"
    lb_port = 443
    lb_protocol = "ssl"
    ssl_certificate_id = "${var.ssl_cert_arn}"
}

  listener {
    instance_port = 2222
    instance_protocol = "tcp"
    lb_port = 2222
    lb_protocol = "tcp"
  }

  tags {
  component = "concourse"
  }
}


# Specify the provider and access details
provider "aws" {
  region = "${var.aws_region}"
  access_key = "${var.aws_access_key}"
  secret_key = "${var.aws_secret_key}"
}

# Create a VPC to launch our instances into
resource "aws_vpc" "default" {
  cidr_block = "10.0.0.0/16"

    tags {
    Name = "bosh-default"
    component = "bosh-director"
  }
}

# Create an internet gateway to give our subnet access to the outside world
resource "aws_internet_gateway" "default" {
  vpc_id = "${aws_vpc.default.id}"
  tags {
  Name = "bosh-default"
  component = "bosh-director"
  }
}

# Grant the VPC internet access on its main route table
resource "aws_route" "internet_access" {
  route_table_id         = "${aws_vpc.default.main_route_table_id}"
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = "${aws_internet_gateway.default.id}"
}

# Create a subnet to launch our instances into
resource "aws_subnet" "default" {
  vpc_id                  = "${aws_vpc.default.id}"
  cidr_block              = "10.0.0.0/24"
  availability_zone = "eu-west-1a"
  depends_on = ["aws_internet_gateway.default"]
  map_public_ip_on_launch = true
  tags {
  Name = "bosh-default"
  component = "bosh-director"
  }
}

# Create an ops_services subnet
resource "aws_subnet" "ops_services" {
  vpc_id                  = "${aws_vpc.default.id}"
  cidr_block              = "10.0.10.0/24"
  availability_zone = "eu-west-1a"
  depends_on = ["aws_internet_gateway.default"]
  map_public_ip_on_launch = true
  tags {
  Name = "ops_services"
  component = "ops_services"
  }
}

# Create an EIP for our Director
resource "aws_eip" "boshdirector" {
    vpc = true
}

# The default security group
resource "aws_security_group" "boshdefault" {
  name        = "boshdefault"
  description = "Default BOSH security group"
  vpc_id      = "${aws_vpc.default.id}"
  tags {
  Name = "bosh-default"
  component = "bosh-director"
  }

	# inbound access rules
  ingress {
    from_port   = 6868
    to_port     = 6868
    protocol    = "tcp"
    cidr_blocks = ["${var.boshers}"]
  }

	ingress {
		from_port   = 25555
		to_port     = 25555
		protocol    = "tcp"
    cidr_blocks = ["${var.boshers}"]
	}

	ingress {
		from_port   = 22
		to_port     = 22
		protocol    = "tcp"
    cidr_blocks = ["${var.boshers}"]
	}

	ingress {
		from_port   = 0
		to_port     = 65535
		protocol    = "tcp"
		self        = true
	}

	ingress {
		from_port   = 0
		to_port     = 65535
		protocol    = "udp"
		self        = true
	}

	# outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}


resource "aws_route53_record" "concourse" {
   zone_id = "${var.ci_dns_zone_id}"
   name = "${var.ci_hostname}"
   type = "CNAME"
   ttl = "300"
   records = ["${aws_elb.concourse.dns_name}"]
}


resource "aws_s3_bucket" "setup-files" {
    bucket = "concourse-setup-files"
    acl = "private"
    region = "eu-west-1"
}


output "security_group_id" {
    value = "${aws_security_group.boshdefault.id}"
}

output "default_subnet_id" {
    value = "${aws_subnet.default.id}"
}

output "ops_services_subnet_id" {
    value = "${aws_subnet.ops_services.id}"
}

output "eip" {
    value = "${aws_eip.boshdirector.public_ip}"
}

response:
To provision a Concourse CI deployment on AWS, we need to set up a robust networking foundation (VPC), security layers, and the compute resources required to run the Concourse web and worker nodes. This configuration includes an Application Load Balancer (ALB) for HTTPS access and an S3 bucket for artifact storage.

```hcl
# Terraform Configuration for Concourse CI on AWS

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- VPC & Networking ---

resource "aws_vpc" "concourse_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "concourse-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.concourse_vpc.id
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.concourse_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags                    = { Name = "concourse-public-${count.index}" }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.concourse_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# --- Security Groups ---

resource "aws_security_group" "alb_sg" {
  name        = "concourse-alb-sg"
  description = "Allow HTTP/S to LB"
  vpc_id      = aws_vpc.concourse_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "concourse_nodes" {
  name        = "concourse-node-sg"
  vpc_id      = aws_vpc.concourse_vpc.id

  # Web UI and API from ALB
  ingress {
    from_port       = 8080
    to_port         = 8080
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  # TSA Tunnel (used by workers)
  ingress {
    from_port   = 2222
    to_port     = 2222
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Storage & S3 ---

resource "aws_s3_bucket" "concourse_assets" {
  bucket        = "concourse-ci-assets-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# --- Load Balancer ---

resource "aws_lb" "concourse_alb" {
  name               = "concourse-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "concourse_web" {
  name     = "concourse-web-tg"
  port     = 8080
  protocol = "HTTP"
  vpc_id   = aws_vpc.concourse_vpc.id

  health_check {
    path = "/api/v1/info"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.concourse_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.concourse_web.arn
  }
}

# --- Route 53 ---

data "aws_route53_zone" "selected" {
  name         = "example.com." # Replace with your domain
  private_zone = false
}

resource "aws_route53_record" "concourse" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "concourse.${data.aws_route53_zone.selected.name}"
  type    = "A"

  alias {
    name                   = aws_lb.concourse_alb.dns_name
    zone_id                = aws_lb.concourse_alb.zone_id
    evaluate_target_health = true
  }
}

# --- Compute (Example EC2 Instance for Web Node) ---

resource "aws_instance" "concourse_web" {
  ami           = "ami-0c7217cdde317cfec" # Amazon Linux 2 (Example ID)
  instance_type = "t3.medium"
  subnet_id     = aws_subnet.public[0].id
  vpc_security_group_ids = [aws_security_group.concourse_nodes.id]

  tags = {
    Name = "concourse-web"
  }

  # IAM profile for S3 access would be defined here
}

resource "aws_lb_target_group_attachment" "concourse_web_attach" {
  target_group_arn = aws_lb_target_group.concourse_web.arn
  target_id        = aws_instance.concourse_web.id
  port             = 8080
}

# --- Outputs ---

output "concourse_url" {
  value = "http://${aws_route53_record.concourse.fqdn}"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.concourse_assets.id
}
```

