To provision a Managed Instance Group (MIG) that runs a container on Google Cloud Platform, we need to define several resources: a Service Account for the instances, a Compute Instance Template that references the container image (using the `gce-container-declaration` format), and the Compute Instance Group Manager itself.

Here is the complete Terraform configuration:

```hcl
# Configure the Google Cloud Provider
provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The ID of the project in which to provision resources."
  type        = string
}

variable "region" {
  description = "The region to deploy the managed instance group."
  type        = string
  default     = "us-central1"
}

variable "container_image" {
  description = "The Docker image to deploy."
  type        = string
  default     = "gcr.io/google-containers/busybox"
}

# 1. Create a Service Account for the VM instances
resource "google_service_account" "mig_service_account" {
  account_id   = "mig-container-sa"
  display_name = "MIG Container Service Account"
}

# 2. Define the Instance Template with Container Metadata
resource "google_compute_instance_template" "container_template" {
  name_prefix  = "container-mig-template-"
  machine_type = "e2-medium"

  # Define the OS as a Container Optimized OS (COS)
  disk {
    source_image = "cos-cloud/cos-stable"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network = "default"
    access_config {
      # Include this block to give instances external IP addresses
    }
  }

  # Metadata required to run the container automatically on COS
  metadata = {
    gce-container-declaration = <<-EOT
      spec:
        containers:
          - name: app-container
            image: ${var.container_image}
            stdin: false
            tty: false
        restartPolicy: Always
    EOT
  }

  service_account {
    email  = google_service_account.mig_service_account.email
    scopes = ["cloud-platform"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

# 3. Create the Managed Instance Group
resource "google_compute_instance_group_manager" "mig" {
  name               = "container-managed-group"
  base_instance_name = "container-vm"
  zone               = "${var.region}-a"
  target_size        = 2

  version {
    instance_template = google_compute_instance_template.container_template.id
  }

  named_port {
    name = "http"
    port = 80
  }
}

# Outputs
output "project_id" {
  value       = var.project_id
  description = "The GCP Project ID."
}

output "instance_group_url" {
  value       = google_compute_instance_group_manager.mig.instance_group
  description = "The URL of the created Instance Group."
}

output "mig_name" {
  value       = google_compute_instance_group_manager.mig.name
  description = "The name of the Managed Instance Group."
}

