response:
To provision a three-node Consul cluster on AWS, we will define a VPC, public subnets, security groups to allow Consul gossip and RPC traffic, and an Auto Scaling Group (or individual instances) with a retry-join mechanism using AWS resource tags.

```hcl
# Configure the AWS Provider
provider "aws" {
  region     = "us-east-1"
  access_key = "YOUR_AWS_ACCESS_KEY"
  secret_key = "YOUR_AWS_SECRET_KEY"
}

# --- Networking ---

resource "aws_vpc" "consul_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags = { Name = "consul-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.consul_vpc.id
}

resource "aws_subnet" "consul_subnet" {
  vpc_id                  = aws_vpc.consul_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"
}

resource "aws_route_table" "rt" {
  vpc_id = aws_vpc.consul_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.consul_subnet.id
  route_table_id = aws_route_table.rt.id
}

# --- Security Groups ---

resource "aws_security_group" "consul_sg" {
  name        = "consul-sg"
  description = "Allow Consul traffic"
  vpc_id      = aws_vpc.consul_vpc.id

  # SSH
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Consul HTTP API
  ingress {
    from_port   = 8500
    to_port     = 8500
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Consul Serf LAN (TCP/UDP)
  ingress {
    from_port   = 8301
    to_port     = 8301
    protocol    = "tcp"
    self        = true
  }
  ingress {
    from_port   = 8301
    to_port     = 8301
    protocol    = "udp"
    self        = true
  }

  # Consul RPC
  ingress {
    from_port   = 8300
    to_port     = 8300
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- IAM Role for Cloud Auto-Join ---

resource "aws_iam_role" "consul_join" {
  name = "consul-join-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

resource "aws_iam_policy" "consul_join" {
  name = "consul-join-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "ec2:DescribeInstances"
      Resource = "*"
    }]
  })
}

resource "aws_iam_role_policy_attachment" "consul_join" {
  role       = aws_iam_role.consul_join.name
  policy_arn = aws_iam_policy.consul_join.arn
}

resource "aws_iam_instance_profile" "consul_join" {
  name = "consul-join-profile"
  role = aws_iam_role.consul_join.name
}

# --- EC2 Instances ---

resource "aws_instance" "consul_server" {
  count                  = 3
  ami                    = "ami-0c55b159cbfafe1f0" # Replace with valid Consul-ready AMI or Ubuntu
  instance_type          = "t2.micro"
  key_name               = "your-ssh-key-name"
  subnet_id              = aws_subnet.consul_subnet.id
  vpc_security_group_ids = [aws_security_group.consul_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.consul_join.name

  tags = {
    Name = "consul-server-${count.index}"
    ConsulCluster = "auto-join"
  }

  # Simplified User Data to install and start Consul
  # This assumes a base Ubuntu image; it installs Consul and uses cloud-auto-join
  user_data = <<-EOF
              #!/bin/bash
              apt-get update
              apt-get install -y unzip curl
              curl -fsSL https://apt.releases.hashicorp.com/gpg | apt-key add -
              apt-add-repository "deb [arch=amd64] https://apt.releases.hashicorp.com $(lsb_release -cs) main"
              apt-get update && apt-get install consul -y

              cat <<CONFIG > /etc/consul.d/consul.hcl
              data_dir = "/opt/consul"
              ui_config {
                enabled = true
              }
              server = true
              bootstrap_expect = 3
              client_addr = "0.0.0.0"
              bind_addr = "0.0.0.0"
              advertise_addr = "$(curl -s http://169.254.169.254/latest/meta-data/local-ipv4)"
              retry_join = ["provider=aws tag_key=ConsulCluster tag_value=auto-join"]
              CONFIG

              systemctl enable consul
              systemctl start consul
              EOF
}

output "consul_ui_endpoints" {
  value = [for i in aws_instance.consul_server : "http://${i.public_ip}:8500"]
}
```

