# --- Provider Configuration ---
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "google" {}

# --- Variables ---
variable "org_id" {
  description = "The organization ID"
  type        = string
}

variable "billing_account" {
  description = "The billing account ID"
  type        = string
}

variable "project_definitions" {
  description = "Map of project keys to their display names"
  type        = map(string)
  default = {
    "frontend" = "Web Portal"
    "backend"  = "Core API"
    "data"     = "Data Warehouse"
  }
}

variable "enabled_apis" {
  description = "List of APIs to enable across all projects"
  type        = list(string)
  default     = ["compute.googleapis.com", "storage.googleapis.com", "iam.googleapis.com"]
}

# --- Resource Generation ---

# 1. Random Suffixes for Unique Project IDs
resource "random_id" "suffix" {
  for_each    = var.project_definitions
  byte_length = 4
}

# 2. Project Creation
resource "google_project" "projects" {
  for_each        = var.project_definitions
  name            = each.value
  project_id      = "${each.key}-${random_id.suffix[each.key].hex}"
  org_id          = var.org_id
  billing_account = var.billing_account
}

# 3. Enable APIs per Project
resource "google_project_service" "services" {
  # Create a flattened map of project-API pairs
  for_each = {
    for pair in setproduct(keys(var.project_definitions), var.enabled_apis) :
    "${pair[0]}-${pair[1]}" => {
      project_id = google_project.projects[pair[0]].project_id
      service    = pair[1]
    }
  }
  project = each.value.project_id
  service = each.value.service

  disable_on_destroy = false
}

# 4. Create Service Accounts
resource "google_service_account" "sa" {
  for_each     = google_project.projects
  account_id   = "admin-sa"
  display_name = "Administrative Service Account"
  project      = each.value.project_id
}

# 5. Assign IAM Roles (Example: Viewer role for the created Service Account)
resource "google_project_iam_member" "sa_roles" {
  for_each = google_project.projects
  project  = each.value.project_id
  role     = "roles/viewer"
  member   = "serviceAccount:${google_service_account.sa[each.key].email}"
}

# 6. Generate Service Account Keys
resource "google_service_account_key" "keys" {
  for_each           = google_service_account.sa
  service_account_id = each.value.name
}

# --- Outputs ---
output "project_ids" {
  value = { for k, v in google_project.projects : k => v.project_id }
}

output "service_account_emails" {
  value = { for k, v in google_service_account.sa : k => v.email }
}

output "service_account_private_keys" {
  sensitive = true
  value     = { for k, v in google_service_account_key.keys : k => v.private_key }
}

response:
To provision multiple Google Cloud projects with random suffixes, specific APIs, service accounts, and IAM roles, we use the `google_project` resource in conjunction with the `random_id` resource for unique naming.

The following configuration demonstrates this automation:

```hcl
# --- Provider Configuration ---
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "google" {}

# --- Variables ---
variable "org_id" {
  description = "The organization ID"
  type        = string
}

variable "billing_account" {
  description = "The billing account ID"
  type        = string
}

variable "project_definitions" {
  description = "Map of project keys to their display names"
  type        = map(string)
  default = {
    "frontend" = "Web Portal"
    "backend"  = "Core API"
    "data"     = "Data Warehouse"
  }
}

variable "enabled_apis" {
  description = "List of APIs to enable across all projects"
  type        = list(string)
  default     = ["compute.googleapis.com", "storage.googleapis.com", "iam.googleapis.com"]
}

# --- Resource Generation ---

# 1. Random Suffixes for Unique Project IDs
resource "random_id" "suffix" {
  for_each    = var.project_definitions
  byte_length = 4
}

# 2. Project Creation
resource "google_project" "projects" {
  for_each        = var.project_definitions
  name            = each.value
  project_id      = "${each.key}-${random_id.suffix[each.key].hex}"
  org_id          = var.org_id
  billing_account = var.billing_account
}

# 3. Enable APIs per Project
resource "google_project_service" "services" {
  # Create a flattened map of project-API pairs
  for_each = {
    for pair in setproduct(keys(var.project_definitions), var.enabled_apis) :
    "${pair[0]}-${pair[1]}" => {
      project_id = google_project.projects[pair[0]].project_id
      service    = pair[1]
    }
  }
  project = each.value.project_id
  service = each.value.service

  disable_on_destroy = false
}

# 4. Create Service Accounts
resource "google_service_account" "sa" {
  for_each     = google_project.projects
  account_id   = "admin-sa"
  display_name = "Administrative Service Account"
  project      = each.value.project_id
}

# 5. Assign IAM Roles (Example: Viewer role for the created Service Account)
resource "google_project_iam_member" "sa_roles" {
  for_each = google_project.projects
  project  = each.value.project_id
  role     = "roles/viewer"
  member   = "serviceAccount:${google_service_account.sa[each.key].email}"
}

# 6. Generate Service Account Keys
resource "google_service_account_key" "keys" {
  for_each           = google_service_account.sa
  service_account_id = each.value.name
}

# --- Outputs ---
output "project_ids" {
  value = { for k, v in google_project.projects : k => v.project_id }
}

output "service_account_emails" {
  value = { for k, v in google_service_account.sa : k => v.email }
}

output "service_account_private_keys" {
  sensitive = true
  value     = { for k, v in google_service_account_key.keys : k => v.private_key }
}
