# Standard AWS Provider configuration
provider "aws" {
  region = "us-east-1"
}

variable "vpc_id" {
  description = "The ID of the VPC where security groups will be created"
  type        = string
}

variable "cluster_name" {
  description = "The name of the Kubernetes cluster for tagging"
  type        = string
  default     = "my-k8s-cluster"
}

# 1. SSH Access Security Group
resource "aws_security_group" "ssh_access" {
  name        = "${var.cluster_name}-ssh-access"
  description = "Allow SSH access from specific CIDR"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Recommendation: Restrict to your specific IP
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name                                        = "${var.cluster_name}-ssh-sg"
    "kubernetes.io/cluster/${var.cluster_name}" = "owned"
  }
}

# 2. External Load Balancer Security Group
resource "aws_security_group" "ext_lb" {
  name        = "${var.cluster_name}-public-lb"
  description = "Allow public web traffic to the Load Balancer"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name                                        = "${var.cluster_name}-lb-sg"
    "kubernetes.io/cluster/${var.cluster_name}" = "owned"
  }
}

# 3. Kubernetes Etcd Security Group
resource "aws_security_group" "etcd" {
  name        = "${var.cluster_name}-etcd"
  description = "Kubernetes etcd cluster communication"
  vpc_id      = var.vpc_id

  # Etcd client requests/peer communication
  ingress {
    from_port   = 2379
    to_port     = 2380
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name                                        = "${var.cluster_name}-etcd-sg"
    "kubernetes.io/cluster/${var.cluster_name}" = "owned"
  }
}

# 4. Worker Nodes Security Group
resource "aws_security_group" "workers" {
  name        = "${var.cluster_name}-worker-nodes"
  description = "Security group for K8s worker nodes"
  vpc_id      = var.vpc_id

  # Allow all traffic between nodes in the same SG (Internal Pod Networking)
  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  # Kubelet API
  ingress {
    from_port   = 10250
    to_port     = 10250
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Assuming internal VPC range
  }

  # NodePort Services (Default range)
  ingress {
    from_port       = 30000
    to_port         = 32767
    protocol        = "tcp"
    security_groups = [aws_security_group.ext_lb.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name                                        = "${var.cluster_name}-worker-sg"
    "kubernetes.io/cluster/${var.cluster_name}" = "owned"
  }
}

