    "kubernetes.io/cluster/${var.cluster_name}" = "owned"
  }
}

# 2. External Load Balancer Security Group
resource "aws_security_group" "ext_lb" {
  name        = "${var.cluster_name}-public-lb"
  description = "Allow public web traffic to the Load Balancer"
  vpc_id      = var.vpc_id

  ingress {
