}

# 4. Worker Nodes Security Group
resource "aws_security_group" "workers" {
  name        = "${var.cluster_name}-worker-nodes"
  description = "Security group for K8s worker nodes"
  vpc_id      = var.vpc_id

  # Allow all traffic between nodes in the same SG (Internal Pod Networking)
